// Sync helpers — write to both localStorage and Supabase
const dbPut = async (table: string, key: string, value: any) => {
  if (!supabase) return;
  try {
    const { error } = await supabase.from(table).upsert({ key, value }, { onConflict: "key" });
    if (error) console.error("[DB] Put error:", table, key, error.message);
    else console.log("[DB] Saved:", table, key);
  } catch (e) { console.error("[DB] Put failed:", table, key, e); }
};
const dbGet = async (table: string, key: string): Promise<any> => {
  if (!supabase) return null;
  try {
    const { data } = await supabase.from(table).select("value").eq("key", key).single();
    return data?.value ?? null;
  } catch { return null; }
};
const dbDelete = async (table: string, key: string) => {
  if (!supabase) return;
  try { await supabase.from(table).delete().eq("key", key); } catch {}
};
const dbGetAll = async (table: string, prefix: string): Promise<{key:string;value:any}[]> => {
  if (!supabase) return [];
  try {
    const { data } = await supabase.from(table).select("key, value").like("key", `${prefix}%`);
    return data || [];
  } catch { return []; }
};

// Pull all cloud data into localStorage on app start
async function syncFromCloud() {
  if (!supabase) return;
  console.log("[DB] Syncing from cloud…");
  // Abort controller for 5s timeout on the entire sync
  const controller = new AbortController();
  const timeout = setTimeout(() => controller.abort(), 5000);
  try {
    // Sync clients
    const clients = await dbGet("app_data", "clients");
    if (controller.signal.aborted) throw new Error("timeout");
    if (clients) localStorage.setItem("b2br_clients", JSON.stringify(clients));
    // Sync users (admin-created)
    const users = await dbGet("app_data", "users");
    if (controller.signal.aborted) throw new Error("timeout");
    if (users) localStorage.setItem("b2br_users", JSON.stringify(users));
    // Sync all workspaces
    const workspaces = await dbGetAll("app_data", "ws_");
    if (controller.signal.aborted) throw new Error("timeout");
    for (const ws of workspaces) {
      const clientId = ws.key.replace("ws_", "");
      localStorage.setItem(`b2br_ws_${clientId}`, JSON.stringify(ws.value));
    }
    // Sync API logs from all users
    if (!controller.signal.aborted) {
      const allLogEntries = await dbGetAll("app_data", "api_logs");
      for (const entry of allLogEntries) {
        localStorage.setItem(`b2br_${entry.key}`, JSON.stringify(entry.value));
      }
    }
    // Sync file blobs (skip if already timed out)
    if (!controller.signal.aborted) {
      const blobs = await dbGetAll("file_blobs", "");
      for (const b of blobs) {
        await idbPut(b.key, b.value);
      }
      console.log("[DB] Cloud sync complete:", workspaces.length, "workspaces,", blobs.length, "files");
    }
  } catch (e) { console.warn("[DB] Cloud sync failed or timed out:", e); }
  clearTimeout(timeout);
}

// Push local data to cloud
// ── Debounced cloud sync: writes locally immediately, batches Supabase pushes ──
const _cloudQueue = new Map<string, { table: string; key: string; value: any }>();
let _cloudFlushTimer: ReturnType<typeof setTimeout> | null = null;
const CLOUD_SYNC_DELAY = 5000; // 5 seconds — batch writes within this window

async function _flushCloudQueue() {
  if (!supabase || _cloudQueue.size === 0) return;
  const batch = Array.from(_cloudQueue.values());
  _cloudQueue.clear();
  console.log(`[DB] Flushing ${batch.length} queued sync(s) to cloud`);
  for (const item of batch) {
    try { await dbPut(item.table, item.key, item.value); }
    catch (e) { console.error("[DB] Cloud sync failed for", item.key, e); }
  }
}

function syncToCloud(key: string, value: any, table = "app_data") {
  if (!supabase) return;
  // Queue the write (overwrites previous pending write for same key)
  _cloudQueue.set(`${table}:${key}`, { table, key, value });
  // Reset the debounce timer
  if (_cloudFlushTimer) clearTimeout(_cloudFlushTimer);
  _cloudFlushTimer = setTimeout(_flushCloudQueue, CLOUD_SYNC_DELAY);
}

// Flush pending writes when user navigates away
if (typeof window !== "undefined") {
  window.addEventListener("beforeunload", () => { _flushCloudQueue(); });
  document.addEventListener("visibilitychange", () => { if (document.visibilityState === "hidden") _flushCloudQueue(); });
}

