async function fetchSlackMessages(channelId: string, oldest?: string): Promise<{ok:boolean; messages:any[]; error?:string}> {
  if (!getSlackToken()) return { ok: false, messages: [], error: "No Slack token configured" };
  if (!channelId) return { ok: false, messages: [], error: "No channel ID" };
  const allMessages: any[] = [];
  let cursor = "";
  let pages = 0;
  const errMap: Record<string, string> = {
    not_in_channel: "Bot is not in this channel. In Slack, go to the channel and type: /invite @CX Tool Sync",
    channel_not_found: "Channel not found. Check the channel ID or make sure the bot has access.",
    invalid_auth: "Invalid Slack bot token. Check your token in Profile → API Keys.",
    missing_scope: "Bot is missing permissions. Add channels:history scope in your Slack app settings.",
    account_inactive: "Slack token has been revoked or the bot was removed.",
    token_revoked: "Slack token has been revoked. Generate a new one in your Slack app settings.",
  };
  try {
    do {
      const params: Record<string, string> = { channel: channelId, limit: "200" };
      if (oldest) params.oldest = oldest;
      if (cursor) params.cursor = cursor;
      const data = await slackApiFetch("conversations.history", params);
      if (!data.ok) return { ok: false, messages: [], error: errMap[data.error] || `Slack error: ${data.error}` };
      allMessages.push(...(data.messages || []));
      cursor = data.response_metadata?.next_cursor || "";
      pages++;
    } while (cursor && pages < 20);
    return { ok: true, messages: allMessages };
  } catch (e: any) {
    return { ok: false, messages: [], error: e.message || "Network error" };
  }
}

async function fetchSlackUsers(): Promise<Record<string, string>> {
  if (!getSlackToken()) return {};
  try {
    const data = await slackApiFetch("users.list", { limit: "200" });
    if (!data.ok) return {};
    const map: Record<string, string> = {};
    for (const u of (data.members || [])) {
      map[u.id] = u.real_name || u.name || u.id;
    }
    return map;
  } catch { return {}; }
}

async function resolveSlackUser(userId: string): Promise<{name:string; isWorkspaceMember:boolean}> {
  try {
    const data = await slackApiFetch("users.info", { user: userId });
    if (data.ok && data.user) {
      return { name: data.user.real_name || data.user.name || userId, isWorkspaceMember: !data.user.is_stranger };
    }
    return { name: userId, isWorkspaceMember: false };
  } catch { return { name: userId, isWorkspaceMember: false }; }
}

async function resolveAllUsers(messages: any[], knownMap: Record<string, string>): Promise<Record<string, {name:string; isCX:boolean}>> {
  const result: Record<string, {name:string; isCX:boolean}> = {};
  // Add known workspace users as CX
  for (const [id, name] of Object.entries(knownMap)) {
    result[id] = { name, isCX: true };
  }
  console.log("[Slack] Known workspace users:", Object.keys(knownMap).length);
  // Collect unknown user IDs from messages
  const unknownIds = new Set<string>();
  for (const m of messages) {
    if (m.user && !result[m.user]) unknownIds.add(m.user);
  }
  console.log("[Slack] Unknown user IDs to resolve:", unknownIds.size, Array.from(unknownIds));
  // Resolve unknown users individually (max 20)
  const toResolve = Array.from(unknownIds).slice(0, 20);
  for (const id of toResolve) {
    const r = await resolveSlackUser(id);
    console.log("[Slack] Resolved", id, "→", r.name, "isWorkspace:", r.isWorkspaceMember);
    result[id] = { name: r.name, isCX: r.isWorkspaceMember };
  }
  // Cache resolved users in localStorage for future syncs
  try {
    const cache = JSON.parse(localStorage.getItem("b2br_slack_user_cache") || "{}");
    for (const [id, info] of Object.entries(result)) { cache[id] = info; }
    localStorage.setItem("b2br_slack_user_cache", JSON.stringify(cache));
  } catch {}
  return result;
}

async function fetchSlackChannels(): Promise<{id:string;name:string;error?:string}[]> {
  if (!getSlackToken()) return [];
  try {
    const all: {id:string;name:string}[] = [];
    let cursor = "";
    do {
      const params: Record<string, string> = { types: "public_channel,private_channel", limit: "200", exclude_archived: "true" };
      if (cursor) params.cursor = cursor;
      const data = await slackApiFetch("conversations.list", params);
      if (!data.ok) {
        // Return a sentinel entry with the error so the UI can show it
        return [{ id: "__error__", name: "", error: data.error || "Unknown Slack error" } as any];
      }
      for (const ch of (data.channels || [])) all.push({ id: ch.id, name: ch.name });
      cursor = data.response_metadata?.next_cursor || "";
    } while (cursor);
    return all.sort((a,b) => a.name.localeCompare(b.name));
  } catch (e: any) {
    console.warn("fetchSlackChannels error:", e);
    return [{ id: "__error__", name: "", error: e.message || "Network error" } as any];
  }
}

// ─── API USAGE LOGGING ───────────────────────────────────────────────────────
// Claude Sonnet 4 pricing: $3/M input, $15/M output
const COST_PER_INPUT_TOKEN = 3 / 1_000_000;
const COST_PER_OUTPUT_TOKEN = 15 / 1_000_000;
let _currentUserId = "";
let _currentUserEmail = "";
function setApiLogUser(id: string, email: string) { _currentUserId = id; _currentUserEmail = email; }

type ApiLog = { id:string; userId:string; userEmail:string; timestamp:string; model:string; action:string;
  inputTokens:number; outputTokens:number; cost:number; durationMs:number };

function logApiCall(inputTokens: number, outputTokens: number, model: string, action: string, durationMs: number) {
  const cost = inputTokens * COST_PER_INPUT_TOKEN + outputTokens * COST_PER_OUTPUT_TOKEN;
  const entry: ApiLog = {
    id: uid(), userId: _currentUserId, userEmail: _currentUserEmail || "unknown",
    timestamp: new Date().toISOString(), model, action,
    inputTokens, outputTokens, cost, durationMs,
  };
  // Save to localStorage
  try {
    const logs: ApiLog[] = JSON.parse(localStorage.getItem("b2br_api_logs") || "[]");
    logs.push(entry);
    // Keep last 2000 entries
    if (logs.length > 2000) logs.splice(0, logs.length - 2000);
    localStorage.setItem("b2br_api_logs", JSON.stringify(logs));
  } catch {}
  // Sync to cloud — use per-user key so logs don't overwrite each other
  const userKey = _currentUserEmail ? `api_logs_${_currentUserEmail.replace(/[^a-z0-9]/gi,"_")}` : "api_logs";
  syncToCloud(userKey, JSON.parse(localStorage.getItem("b2br_api_logs") || "[]"));
}

function loadApiLogs(): ApiLog[] {
  try {
    // Merge local logs + any cloud-synced user logs
    const local: ApiLog[] = JSON.parse(localStorage.getItem("b2br_api_logs") || "[]");
    const allLogs = [...local];
    const localIds = new Set(local.map(l => l.id));
    // Check for cloud-synced logs from other users
    for (let i = 0; i < localStorage.length; i++) {
      const key = localStorage.key(i);
      if (key && key.startsWith("b2br_api_logs_") && key !== "b2br_api_logs") {
        try {
          const userLogs: ApiLog[] = JSON.parse(localStorage.getItem(key) || "[]");
          for (const log of userLogs) {
            if (!localIds.has(log.id)) { allLogs.push(log); localIds.add(log.id); }
          }
        } catch {}
      }
    }
    return allLogs.sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime());
  } catch { return []; }
}

// ─── FULL WORKSPACE CONTEXT ──────────────────────────────────────────────────
// Pure function that assembles a comprehensive context string from all workspace data.
// Consumed by callAI (via useFullContext flag) to give every AI generator full visibility.
// The returned string is identical within a session (assuming unchanged data), so the
// Anthropic prompt cache can hit when sent as a cache_control: "ephemeral" block.
function buildFullContext(d: any): string {
  if (!d) return "";
  const parts: string[] = [];
  const push = (title: string, body: string) => { if (body && body.trim()) parts.push(`\n## ${title}\n${body}`); };
  const cd = d.companyData || {};
  // Company
  const coLines = Object.entries(cd).filter(([k, v]) => !k.startsWith("_") && v && String(v).trim()).map(([k, v]) => `${k}: ${String(v).slice(0, 800)}`);
  if (coLines.length) push("COMPANY PROFILE", coLines.join("\n"));
  // Products
  if (d.products?.length) push("PRODUCTS / SERVICES", d.products.map((p: any, i: number) => `${i + 1}. ${p.name} (${p.category || "?"})\n  Description: ${p.description || ""}\n  Problems solved: ${p.problemsSolved || ""}\n  Value prop: ${p.valueProposition || ""}\n  Ideal customer: ${p.idealCustomer || ""}\n  Competitors: ${p.competitors || ""}\n  Deal type: ${p.dealType || ""}  ACV: ${p.acv || ""}  LTV: ${p.ltv || ""}`).join("\n\n"));
  // Personas
  if (d.personas?.length) push("PERSONAS / ICPs", d.personas.map((p: any, i: number) => {
    const pd = p.data || {};
    return `${i + 1}. ${p.name}\n  Buyer: ${pd.buyer || ""}\n  Industries: ${pd.industries || ""}\n  Size: ${(pd.co_sizes || []).join(", ")}  Geo: ${pd.geo || ""}\n  Primary pain: ${pd.pain1 || ""}\n  Secondary pain: ${pd.pain2 || ""}\n  Goals: ${pd.goals || ""}\n  Triggers: ${pd.triggers || ""}\n  Objections: ${pd.objections || ""}\n  Best channel: ${pd.best_channel || ""}  Tone: ${pd.tone || ""}  CTA: ${pd.cta || ""}\n  Why we win: ${pd.why_client_wins || ""}`;
  }).join("\n\n"));
  // Offers
  if (d.offers?.length) push("OFFERS", d.offers.map((o: any) => {
    const prod = d.products?.find((p: any) => p.id === o.productId);
    const pers = d.personas?.find((p: any) => p.id === o.personaId);
    return `[${o.tier || "?"}] ${prod?.name || "?"} × ${pers?.name || "?"}: "${o.ctaText || o.name || ""}" — ${o.whatTheyGet || ""}`;
  }).join("\n"));
  // Campaigns
  if (d.campaigns?.length) push("CAMPAIGNS", d.campaigns.map((c: any) => {
    const persName = (d.personas || []).find((p:any) => p.id === (c.personaIds||[])[0])?.name || c.personaIds?.[0] || "?";
    const prodName = (d.products || []).find((p:any) => p.id === c.productId)?.name || c.productId || "?";
    const offer = (d.offers || []).find((o:any) => o.id === c.offerId);
    const offerStr = offer ? `${offer.tier || "?"} — "${offer.ctaText || offer.name || ""}"` : (c.offerId || "?");
    const m = c.performance?.metrics || {};
    const hasMetrics = (m.sent || m.allReplies || m.meetings);
    const metricsStr = hasMetrics
      ? ` | METRICS: sent=${m.sent||0} delivered=${m.delivered||0} bounce=${m.bounce||0} replies=${m.allReplies||0} (interested=${m.opportunityReplies||0}, not-interested=${m.notInterestedReplies||0}, OOO=${m.oooReplies||0}, wrong-person=${m.wrongPersonReplies||0}) opens=${m.opens||0} meetings=${m.meetings||0}`
      : "";
    const timePeriodStr = c.performance?.timePeriod?.label ? ` [period: ${c.performance.timePeriod.label}]` : "";
    const importedStr = c.performance?.source === "imported_external" ? " [IMPORTED]" : "";
    const seqStr = c.sequence?.length ? ` | ${c.sequence.length} steps` : "";
    const iterStr = (c.iterations||[]).length ? ` | iterations: ${(c.iterations||[]).length}` : "";
    const goalStr = c.goal ? ` | Goal: ${c.goal.slice(0,140)}` : "";
    const playbookStr = c.playbook && c.playbook !== "auto" ? ` | Playbook: ${c.playbook}` : "";
    const rtsStr = (c.intentTier === "high" || c.rtsListId) ? ", INTENT: HIGH (RTS)" : "";
    // Full sequence content — subject + body per step, with variants. The copilot needs the entire email
    // body to answer "why is step 2 underperforming" / "rewrite the breakup email" / "what's the CTA" questions.
    // Bodies are NOT truncated — the whole email matters.
    let sequenceContent = "";
    if (c.sequence?.length) {
      const stepLines = c.sequence.map((s:any, idx:number) => {
        const day = Number.isFinite(s.dayOffset) ? `Day +${s.dayOffset}` : "";
        const role = s.role ? ` · ${s.role}` : "";
        const subj = s.subject ? `\n    Subject: ${s.subject}` : "";
        const body = s.body ? `\n    Body:\n${String(s.body).split(/\n/).map(l => `      ${l}`).join("\n")}` : "";
        const variants = (s.variants || []).length
          ? "\n    Variants:\n" + s.variants.map((v:any) => {
              const vSubj = v.subject ? `\n        Subject: ${v.subject}` : "";
              const vBody = v.body ? `\n        Body:\n${String(v.body).split(/\n/).map((l:string)=>`          ${l}`).join("\n")}` : "";
              return `      [${v.label||"Variant"} · testing ${v.testVariable||"?"}]${vSubj}${vBody}`;
            }).join("\n")
          : "";
        return `  Step ${s.stepNumber || idx+1} (${day}${role}):${subj}${body}${variants}`;
      }).join("\n");
      sequenceContent = `\n  SEQUENCE:\n${stepLines}`;
    }
    // Contact sample summary — listed inline so the copilot can cite specific rows (e.g. "most of your contacts are CFOs at mid-market SaaS")
    let contactSampleStr = "";
    if (c.contactSample?.rows?.length) {
      const cs = c.contactSample;
      const previewRows = cs.rows.slice(0, 15).map((r:any, i:number) => {
        const cells = cs.headers.map((h:string) => `${h}=${String(r[h] ?? "").slice(0, 60)}`).join(", ");
        return `    ${i+1}. ${cells}`;
      }).join("\n");
      const remaining = cs.rows.length > 15 ? `\n    … and ${cs.rows.length - 15} more row(s) in sample` : "";
      contactSampleStr = `\n  CONTACT SAMPLE (${cs.rows.length}/${cs.totalRows} rows from "${cs.fileName}" — columns: ${cs.headers.join(", ")}):\n${previewRows}${remaining}`;
    }
    return `[${c.status || "?"}] ${c.name || "Untitled"}${importedStr}${timePeriodStr} — Persona: ${persName}, Product: ${prodName}, Offer: ${offerStr}, Channel: ${c.channel || c.type || "?"}${rtsStr}${seqStr}${iterStr}${playbookStr}${goalStr}${metricsStr}${sequenceContent}${contactSampleStr}`;
  }).join("\n"));
  // RTS lists — high-intent, triple-qualified, refreshed daily. Different playbook from cold.
  if (d.rtsLists?.length) push("RTS LISTS (HIGH-INTENT)", d.rtsLists.map((l: any, i: number) => {
    const b = l.bebopSetup || {};
    const linkedCount = (l.linkedCampaignIds || []).length;
    return `${i + 1}. "${l.name}" · ${linkedCount} campaign${linkedCount!==1?"s":""}\n  Goal: ${b.campaignGoal || ""}\n  Selling: ${b.sellingDescription || ""}\n  ICP / signal: ${(b.customerProfile || "").slice(0, 400)}${b.customerProfile && b.customerProfile.length > 400 ? "..." : ""}\n  Competitors: ${b.competitorUrls || ""} · Methodologies: ${b.salesMethodologies || ""}`;
  }).join("\n\n") + `\n\nHIGH-INTENT PLAYBOOK REMINDER: RTS leads are ALREADY showing buying signals. When advising on these lists or campaigns linked to them, use: 2-3 touch sequences (not 5), direct meeting ask from touch 1 (no soft content offers), reference the signal explicitly, short test window (1-2 days), expect 2-4× cold benchmarks. If an RTS campaign underperforms, pivot the SIGNAL/targeting before rewriting copy.`);
  // Strategy
  if (d.strategy) push("STRATEGY ROADMAP", JSON.stringify(d.strategy).slice(0, 3000));
  // Playbooks
  if (d.playbooks?.length) push("PLAYBOOKS", d.playbooks.map((p: any, i: number) => `${i + 1}. ${p.name || `Playbook ${i + 1}`}: objections=${(p.objections || []).length}, signals=${(p.signals || []).length}`).join("\n"));
  // Battlecards
  if (d.battlecards?.length) push("BATTLECARDS", d.battlecards.map((b: any) => `${b.competitorName || "?"}: strengths=${(b.strengths || "").slice(0, 120)} | weaknesses=${(b.weaknesses || "").slice(0, 120)} | displacement=${(b.displacementAngles || "").slice(0, 120)}`).join("\n"));
  // Content assets (Knowledge Center links)
  if (d.contentAssets?.length) push("CONTENT ASSETS / KNOWLEDGE LINKS", d.contentAssets.slice(0, 30).map((c: any) => `- ${c.title || c.url || "Untitled"} (${c.type || "other"}): ${c.description || ""}`).join("\n"));
  // Knowledge Center files
  if (d.wsFiles?.length) push("KNOWLEDGE CENTER FILES", d.wsFiles.slice(0, 20).map((f: any) => `- ${f.name || "?"}: ${(f.content || f.text || "").slice(0, 400)}`).join("\n"));
  if (d.wsLinks?.length) push("KNOWLEDGE CENTER LINKS", d.wsLinks.slice(0, 20).map((l: any) => `- ${l.title || l.url}: ${l.description || ""}`).join("\n"));
  // ROI + DFY
  if (d.roiConfig) push("ROI CONFIG", JSON.stringify(d.roiConfig).slice(0, 500));
  if (d.dfySetup) push("DFY SETUP", JSON.stringify(d.dfySetup).slice(0, 800));
  // Performance logs
  if (d.perfLogs?.length) push("PERFORMANCE LOGS (recent)", d.perfLogs.slice(0, 12).map((p: any) => {
    const m = p.metrics || {};
    return `[${p.date || "?"}] sent=${m.sent || 0} opens=${m.opens || 0} replies=${m.replies || 0} meetings=${m.meetings || 0} revenue=${m.revenue || 0}`;
  }).join("\n"));
  // Call records (summaries + recent transcripts)
  if (d.callRecords?.length) {
    push("CALL RECORDS (summaries)", d.callRecords.slice(0, 20).map((r: any) => `[${r.callDate || "?"}] ${r.callType || "?"} — Score: ${r.result?.overallScore || "?"}/100, Sentiment: ${r.result?.sentiment?.score || "?"}/10, Grade: ${r.result?.grade || "?"}`).join("\n"));
    const recent = [...d.callRecords].sort((a: any, b: any) => new Date(b.callDate || b.scoredAt).getTime() - new Date(a.callDate || a.scoredAt).getTime()).slice(0, 3);
    push("RECENT CALL TRANSCRIPTS (top 3, truncated)", recent.map((r: any) => `\n[${r.callDate || "?"}] ${r.callType || "?"}\n${(r.transcript || "").slice(0, 3500)}${r.transcript?.length > 3500 ? "\n...(truncated)" : ""}`).join("\n"));
  }
  // Communications (Slack / Email / HubSpot)
  if (d.slackComms?.length) {
    const slackDays = d.slackComms.filter((c: any) => c.type === "slack");
    const slackMsgs = slackDays.reduce((s: number, c: any) => s + (c.messageCount || 0), 0);
    const emailCount = d.slackComms.filter((c: any) => c.type === "email").length;
    push("CLIENT COMMUNICATIONS", `${slackMsgs} Slack messages (${slackDays.length} days) · ${emailCount} emails\n` + d.slackComms.slice(0, 30).map((c: any) => {
      const clean = (c.content || "").replace(/<[^>]+>/g, "").replace(/\s+/g, " ").slice(0, 400);
      return `[${c.type}${c.source ? "/" + c.source : ""} ${c.date || "?"}] ${c.subject ? c.subject + " — " : ""}${clean}`;
    }).join("\n"));
  }
  // AI analyses
  if (d.sentiment) {
    const s = d.sentiment;
    push("SENTIMENT ANALYSIS", `Overall: ${s.overallSentiment?.score}/10 (${s.overallSentiment?.label}) trend: ${s.overallSentiment?.trend}\n${s.overallSentiment?.summary || ""}\nRisks: ${(s.riskSignals || []).map((r: any) => `[${r.severity}] ${r.signal}`).join("; ")}\nRecs: ${(s.recommendations || []).map((r: any) => `[${r.priority}] ${r.action}`).join("; ")}`);
  }
  if (d.pitch) {
    const p = d.pitch;
    push("PITCH ANALYSIS", `Score: ${p.overallScore}/100 (${p.grade})\nOptimized pitch: ${p.rewrittenPitch || ""}\nTalking points: ${(p.talkingPoints || []).join("; ")}\nStop saying: ${(p.avoidList || []).join("; ")}\nCTA: ${p.callToAction?.assessment || ""}`);
  }
  if (d.coaching) {
    const c = d.coaching;
    push("CSM COACHING", `${c.overallAssessment || ""}\nCritical fixes: ${(c.criticalFixes || []).map((f: any) => f.issue).join("; ")}\nSkills: ${Object.entries(c.conversationSkills || {}).map(([k, v]: any) => `${k}=${v.score}`).join(", ")}`);
  }
  if (d.intel) {
    const i = d.intel;
    push("CLIENT INTEL", `${i.quickReference?.oneLiner || ""}\nGolden rule: ${i.quickReference?.goldenRule || ""}\nNever: ${i.quickReference?.avoid || ""}\nDecision: ${i.decisionMaking?.style || ""} — ${i.decisionMaking?.description || ""}\nObjections: ${(i.objections || []).map((o: any) => `${o.objection}(${o.status})`).join("; ")}`);
  }
  if (d.stratAnalysis) {
    const s = d.stratAnalysis;
    push("STRATEGIC ANALYSIS", `Health: ${s.overallHealth?.score}/10 — ${s.overallHealth?.oneLiner || ""}\nPositioning: ${s.positioning?.assessment || ""}\nPivots: ${(s.strategicPivots || []).map((p: any) => p.title).join("; ")}`);
  }
  // HubSpot properties — READ-ONLY
  const hsProps = cd._hubspotProps;
  if (hsProps && Object.keys(hsProps).length > 0) {
    const meaningful = Object.entries(hsProps).filter(([k, v]) => v != null && v !== "" && !k.startsWith("hs_") && !k.startsWith("notes_")).slice(0, 120);
    if (meaningful.length) push("HUBSPOT COMPANY DATA (READ-ONLY)", meaningful.map(([k, v]) => `${k}: ${String(v).slice(0, 200)}`).join("\n"));
  }
  return parts.join("\n");
}

// Read full context from the window-stored workspace snapshot (set by AppMain useEffect)
function getFullContext(): string {
  return (window as any).__workspaceCtx || "";
}

// Model options:
//   "claude-sonnet-4-6"      — default. Strongest reasoning, best for synthesis + voice-sensitive generation.
//   "claude-haiku-4-5-20251001" — ~1/3 cost of Sonnet. Use for structured extraction, classification, JSON
//                                reformatting, single-field fills, and scoring tasks where quality is
//                                near-identical to Sonnet but cost matters.
type ClaudeModel = "claude-sonnet-4-6" | "claude-haiku-4-5-20251001";
async function callAI(prompt: string, sys = "", tokens = 800, optionsOrRetries: number | { retries?: number; useFullContext?: boolean; images?: Array<{mediaType:string; base64:string}>; model?: ClaudeModel } = 5) {
  const key = getApiKey();
  if (!key) { alert("Please enter your Anthropic API key first (top-right corner)."); return ""; }
  const _retries = typeof optionsOrRetries === "number" ? optionsOrRetries : (optionsOrRetries?.retries ?? 5);
  const _useFullContext = typeof optionsOrRetries === "object" && optionsOrRetries?.useFullContext === true;
  const _images = (typeof optionsOrRetries === "object" && optionsOrRetries?.images) || [];
  const _model: ClaudeModel = (typeof optionsOrRetries === "object" && optionsOrRetries?.model) || "claude-sonnet-4-6";
  const fullCtx = _useFullContext ? getFullContext() : "";
  // Build messages: if using full context, prepend it as a cacheable block so the same context
  // across many calls hits the Anthropic ephemeral cache (5-min TTL).
  const userContent: any = (fullCtx || _images.length > 0)
    ? [
        ...(fullCtx ? [{ type: "text", text: `WORKSPACE CONTEXT (read-only snapshot):\n${fullCtx}`, cache_control: { type: "ephemeral", ttl: "1h" } }] : []),
        ..._images.map(img => ({ type: "image", source: { type: "base64", media_type: img.mediaType, data: img.base64 } })),
        { type: "text", text: prompt },
      ]
    : prompt;
  const startTime = Date.now();
  for (let attempt = 0; attempt <= _retries; attempt++) {
    try {
      const r = await fetch("https://api.anthropic.com/v1/messages", {
        method:"POST",
        headers:{
          "Content-Type":"application/json",
          "x-api-key": key,
          "anthropic-version": "2023-06-01",
          "anthropic-beta": "extended-cache-ttl-2025-04-11",
          "anthropic-dangerous-direct-browser-access": "true",
        },
        body: JSON.stringify({
          model: _model, max_tokens: tokens,
          system: sys || "You are a senior B2B cold outreach strategist. Be direct, specific, no filler.",
          messages:[{ role:"user", content: userContent }],
        }),
      });
      if (r.status === 429 || r.status === 529 || r.status >= 500) {
        const retryAfter = parseFloat(r.headers.get("retry-after") || "0");
        const delay = Math.max(retryAfter * 1000, Math.min(1000 * Math.pow(2, attempt), 30000));
        console.warn(`callAI rate-limited (${r.status}), retrying in ${delay}ms (attempt ${attempt + 1}/${_retries})`);
        if (attempt < _retries) { await new Promise(ok => setTimeout(ok, delay)); continue; }
        return `Error: Rate limited after ${_retries} retries`;
      }
      const json = await r.json();
      if (json.error) {
        console.error("Anthropic error:", json.error);
        if (json.error.message?.includes("credit balance")) {
          alert("⚠️ Anthropic API credit balance is too low. Please add credits at console.anthropic.com/settings/billing");
        }
        return `Error: ${json.error.message}`;
      }
      // Log usage
      const usage = json.usage;
      if (usage) logApiCall(usage.input_tokens||0, usage.output_tokens||0, json.model||"claude-sonnet-4", prompt.slice(0,60), Date.now()-startTime);
      return json.content?.[0]?.text ?? "";
    } catch(e) {
      if (attempt < _retries) { await new Promise(ok => setTimeout(ok, 1000 * Math.pow(2, attempt))); continue; }
      console.error("callAI failed:", e); return "";
    }
  }
  return "";
}

async function callAIStream(
  messages: { role: "user" | "assistant"; content: string | any[] }[],
  sys: string,
  tokens: number,
  onChunk: (text: string) => void,
  _retries = 5
): Promise<void> {
  const key = getApiKey();
  if (!key) { alert("Please enter your Anthropic API key first."); return; }
  const startTime = Date.now();
  for (let attempt = 0; attempt <= _retries; attempt++) {
    try {
      const r = await fetch("https://api.anthropic.com/v1/messages", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          "x-api-key": key,
          "anthropic-version": "2023-06-01",
          "anthropic-dangerous-direct-browser-access": "true",
        },
        body: JSON.stringify({
          model: "claude-sonnet-4-6",
          max_tokens: tokens,
          system: sys,
          messages,
          stream: true,
        }),
      });
      if (r.status === 429 || r.status === 529 || r.status >= 500) {
        const retryAfter = parseFloat(r.headers.get("retry-after") || "0");
        const delay = Math.max(retryAfter * 1000, Math.min(1000 * Math.pow(2, attempt), 30000));
        console.warn(`callAIStream rate-limited (${r.status}), retrying in ${delay}ms (attempt ${attempt + 1}/${_retries})`);
        if (attempt < _retries) { await new Promise(ok => setTimeout(ok, delay)); continue; }
        return;
      }
      if (!r.body) return;
      const reader = r.body.getReader();
      const decoder = new TextDecoder();
      let buffer = "";
      while (true) {
        const { done, value } = await reader.read();
        if (done) break;
        buffer += decoder.decode(value, { stream: true });
        const lines = buffer.split("\n");
        buffer = lines.pop() ?? "";
        for (const line of lines) {
          if (!line.startsWith("data: ")) continue;
          const data = line.slice(6).trim();
          if (data === "[DONE]") continue;
          try {
            const evt = JSON.parse(data);
            if (evt.type === "content_block_delta" && evt.delta?.type === "text_delta") {
              onChunk(evt.delta.text);
            }
            if (evt.type === "message_delta" && evt.usage) {
              logApiCall(evt.usage.input_tokens||0, evt.usage.output_tokens||0, "claude-sonnet-4-stream", "stream", Date.now()-startTime);
            }
          } catch {}
        }
      }
      return;
    } catch (e) {
      if (attempt < _retries) { await new Promise(ok => setTimeout(ok, 1000 * Math.pow(2, attempt))); continue; }
      console.error("callAIStream failed:", e);
    }
  }
}

