// Stream AI response with tool-use support, returns { text, toolCalls }
async function callAIStreamWithTools(
  messages: { role: string; content: any }[],
  sys: string,
  tokens: number,
  tools: any[],
  onTextChunk: (text: string) => void,
  _retries = 5
): Promise<{ text: string; toolCalls: { id: string; name: string; input: any }[] }> {
  const key = getApiKey();
  if (!key) { alert("Please enter your Anthropic API key first."); return { text: "", toolCalls: [] }; }
  const startTime = Date.now();
  for (let attempt = 0; attempt <= _retries; attempt++) {
    try {
      const r = await fetch("https://api.anthropic.com/v1/messages", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          "x-api-key": key,
          "anthropic-version": "2023-06-01",
          "anthropic-dangerous-direct-browser-access": "true",
        },
        body: JSON.stringify({
          model: "claude-sonnet-4-6",
          max_tokens: tokens,
          system: sys,
          messages,
          tools,
          stream: true,
        }),
      });
      if (r.status === 429 || r.status === 529 || r.status >= 500) {
        const retryAfter = parseFloat(r.headers.get("retry-after") || "0");
        const delay = Math.max(retryAfter * 1000, Math.min(1000 * Math.pow(2, attempt), 30000));
        if (attempt < _retries) { await new Promise(ok => setTimeout(ok, delay)); continue; }
        return { text: "", toolCalls: [] };
      }
      if (!r.body) return { text: "", toolCalls: [] };
      const reader = r.body.getReader();
      const decoder = new TextDecoder();
      let buffer = "";
      let fullText = "";
      const toolCalls: { id: string; name: string; input: any }[] = [];
      let currentToolId = "";
      let currentToolName = "";
      let currentToolJson = "";
      let inToolUse = false;
      while (true) {
        const { done, value } = await reader.read();
        if (done) break;
        buffer += decoder.decode(value, { stream: true });
        const lines = buffer.split("\n");
        buffer = lines.pop() ?? "";
        for (const line of lines) {
          if (!line.startsWith("data: ")) continue;
          const data = line.slice(6).trim();
          if (data === "[DONE]") continue;
          try {
            const evt = JSON.parse(data);
            if (evt.type === "content_block_start") {
              if (evt.content_block?.type === "tool_use") {
                inToolUse = true;
                currentToolId = evt.content_block.id;
                currentToolName = evt.content_block.name;
                currentToolJson = "";
              }
            }
            if (evt.type === "content_block_delta") {
              if (evt.delta?.type === "text_delta") {
                fullText += evt.delta.text;
                onTextChunk(evt.delta.text);
              }
              if (evt.delta?.type === "input_json_delta") {
                currentToolJson += evt.delta.partial_json;
              }
            }
            if (evt.type === "content_block_stop" && inToolUse) {
              try {
                const input = JSON.parse(currentToolJson);
                toolCalls.push({ id: currentToolId, name: currentToolName, input });
              } catch { toolCalls.push({ id: currentToolId, name: currentToolName, input: {} }); }
              inToolUse = false;
            }
            if (evt.type === "message_delta" && evt.usage) {
              logApiCall(evt.usage.input_tokens||0, evt.usage.output_tokens||0, "claude-sonnet-4-stream", "copilot-tools", Date.now()-startTime);
            }
          } catch {}
        }
      }
      return { text: fullText, toolCalls };
    } catch (e) {
      if (attempt < _retries) { await new Promise(ok => setTimeout(ok, 1000 * Math.pow(2, attempt))); continue; }
      console.error("callAIStreamWithTools failed:", e);
    }
  }
  return { text: "", toolCalls: [] };
}

// Fetch a page via r.jina.ai — a free "reader" service that runs the page through a
// headless browser and returns clean markdown. We wrap the markdown in a minimal HTML
// shell (converting # / ## / ### to h1/h2/h3) so the existing htmlToText + structure
// extractor keep working without special-casing markdown downstream.
async function fetchRenderedPage(url: string): Promise<string> {
  try {
    const r = await fetch(`https://r.jina.ai/${url}`, { signal: AbortSignal.timeout(20000) });
    if (!r.ok) { console.warn(`[fetch-rendered] r.jina.ai HTTP ${r.status} for ${url}`); return ""; }
    const md = await r.text();
    if (!md || md.length < 200) return "";
    // Markdown → minimal HTML shell so H-tag extraction still works.
    const escapeAttr = (s:string) => s.replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;");
    let html = escapeAttr(md)
      .replace(/^#### (.+)$/gm, '<h4>$1</h4>')
      .replace(/^### (.+)$/gm, '<h3>$1</h3>')
      .replace(/^## (.+)$/gm, '<h2>$1</h2>')
      .replace(/^# (.+)$/gm, '<h1>$1</h1>')
      .replace(/\n\n/g, '</p><p>');
    html = `<html><body><p>${html}</p></body></html>`;
    console.log(`[fetch-rendered] ✓ r.jina.ai returned ${md.length} chars markdown for ${url}`);
    return html;
  } catch (e:any) {
    console.warn(`[fetch-rendered] r.jina.ai threw for ${url}:`, e?.message || e);
    return "";
  }
}

// Heuristic: does this HTML look like a JS-rendered shell with no useful content?
// Used to decide whether to fall back to a headless-render fetch.
function looksEmptyShell(html: string): boolean {
  if (!html) return true;
  try {
    const doc = new DOMParser().parseFromString(html, "text/html");
    doc.querySelectorAll("script,style,noscript,svg,iframe").forEach(el => el.remove());
    const text = (doc.body?.textContent || "").replace(/\s+/g, " ").trim();
    const headings = doc.querySelectorAll("h1, h2, h3").length;
    // Classic SPA shells: <div id="root"> / <div id="__next"> / <div id="app"> with very little body text
    // OR a page that loads but has no headings and minimal text = probably JS-rendered
    return (text.length < 1200) || (text.length < 3000 && headings < 2);
  } catch { return false; }
}

// Fetch a web page's raw HTML via CORS proxy (tries multiple proxies).
// If all proxies fail OR the returned HTML is an empty JS shell, falls back to r.jina.ai
// which does server-side headless rendering.
async function fetchPageHTML(url: string): Promise<string> {
  // Try the given URL first, then fall back to www. variant (or bare if www. was given) —
  // many sites have SSL certs only valid for the www. subdomain (or vice versa).
  const variants: string[] = [url];
  try {
    const u = new URL(url);
    if (u.hostname.startsWith("www.")) {
      const bare = new URL(url); bare.hostname = u.hostname.slice(4); variants.push(bare.toString());
    } else {
      const www = new URL(url); www.hostname = "www." + u.hostname; variants.push(www.toString());
    }
  } catch {}

  const proxies: { name:string; make:(u:string)=>string }[] = [
    { name:"corsproxy.io", make:(u:string) => `https://corsproxy.io/?${encodeURIComponent(u)}` },
    { name:"codetabs",     make:(u:string) => `https://api.codetabs.com/v1/proxy/?quest=${encodeURIComponent(u)}` },
    { name:"allorigins",   make:(u:string) => `https://api.allorigins.win/raw?url=${encodeURIComponent(u)}` },
    { name:"thingproxy",   make:(u:string) => `https://thingproxy.freeboard.io/fetch/${u}` },
  ];
  let bestProxyHtml = "";
  for (const variantUrl of variants) {
    for (const p of proxies) {
      try {
        const r = await fetch(p.make(variantUrl), { signal: AbortSignal.timeout(8000) });
        if (!r.ok) { console.warn(`[fetch] ${p.name} HTTP ${r.status} for ${variantUrl}`); continue; }
        const html = await r.text();
        if (!html || html.length < 200) { console.warn(`[fetch] ${p.name} empty for ${variantUrl} (${html?.length||0} chars)`); continue; }
        if (html.includes("error code:") || html.includes("Please verify you are human")) { console.warn(`[fetch] ${p.name} blocked for ${variantUrl}`); continue; }
        // Detect 404-style stub pages (common when CORS proxy gets a redirect/error and serves a site-wide error page)
        const lowerHtml = html.toLowerCase();
        if ((lowerHtml.includes("404") || lowerHtml.includes("page not found") || lowerHtml.includes("doesn't exist")) && html.length < 5000) {
          console.warn(`[fetch] ${p.name} returned a 404-like stub for ${variantUrl} (${html.length} chars)`);
          continue;
        }
        console.log(`[fetch] ✓ ${p.name} returned ${html.length} chars for ${variantUrl}`);
        // If this looks like a good static fetch, return it immediately.
        if (!looksEmptyShell(html)) return html;
        // Otherwise keep it as a fallback candidate and try other proxies / rendered path.
        if (html.length > bestProxyHtml.length) bestProxyHtml = html;
        console.warn(`[fetch] ${p.name} returned an empty-shell-looking page (${html.length} chars) — will try rendered fallback if nothing better emerges`);
      } catch (e:any) {
        console.warn(`[fetch] ${p.name} threw for ${variantUrl}:`, e?.message || e);
      }
    }
  }
  // All proxies either failed or returned JS shells — try the headless renderer.
  console.log(`[fetch] Falling back to r.jina.ai for ${url} (proxies returned ${bestProxyHtml.length} chars, shell-like)`);
  const rendered = await fetchRenderedPage(url);
  if (rendered) return rendered;
  // If rendered also fails, return whatever shell we got (better than nothing).
  if (bestProxyHtml) return bestProxyHtml;
  console.error(`[fetch] ALL proxies AND rendered fallback failed for ${url}`);
  return "";
}

// Extract text content from HTML
function htmlToText(html: string, maxLen = 6000): string {
  const doc = new DOMParser().parseFromString(html, "text/html");
  doc.querySelectorAll("script,style,noscript,svg,iframe").forEach(el => el.remove());
  return (doc.body?.textContent || "").replace(/\s+/g, " ").trim().slice(0, maxLen || 10000);
}

// Extract the "offering structure" from an HTML page — nav items + heading hierarchy.
// This is passed to the research-brief prompt as a LABELED STRUCTURE block so the AI
// can read the site's offering taxonomy directly from DOM semantics instead of inferring
// it from free-form body text (which is where hallucinations creep in).
function extractOfferingStructure(html: string): string {
  try {
    const doc = new DOMParser().parseFromString(html, "text/html");
    doc.querySelectorAll("script,style,noscript,svg,iframe").forEach(el => el.remove());
    const lines: string[] = [];
    const clean = (s: string) => s.replace(/\s+/g, " ").trim();

    // Nav/header anchor text — companies list their offerings as nav dropdowns
    const navItems: string[] = [];
    const seenNav = new Set<string>();
    doc.querySelectorAll("nav a, header a, [role='navigation'] a, [class*='menu'] a, [class*='nav'] a").forEach(a => {
      const text = clean(a.textContent || "");
      const key = text.toLowerCase();
      if (text && text.length >= 2 && text.length <= 60 && !seenNav.has(key)) {
        seenNav.add(key);
        navItems.push(text);
      }
    });
    if (navItems.length) lines.push(`NAV ITEMS (${navItems.length}): ${navItems.slice(0, 60).join(" | ")}`);

    // Heading hierarchy — H1/H2/H3/H4 capture the "Solutions / Services" section structure
    const headings: string[] = [];
    doc.querySelectorAll("h1, h2, h3, h4").forEach(h => {
      const text = clean(h.textContent || "");
      if (text && text.length >= 2 && text.length <= 140) {
        headings.push(`${h.tagName}: ${text}`);
      }
    });
    if (headings.length) lines.push(`HEADINGS (${headings.length}):\n${headings.slice(0, 80).join("\n")}`);

    return lines.length ? lines.join("\n") : "";
  } catch { return ""; }
}

// Extract all links from HTML, resolve relative URLs
function extractLinks(html: string, baseUrl: string): {href:string; text:string}[] {
  const doc = new DOMParser().parseFromString(html, "text/html");
  const links: {href:string; text:string}[] = [];
  const seen = new Set<string>();
  doc.querySelectorAll("a[href]").forEach(a => {
    try {
      const href = new URL((a as HTMLAnchorElement).getAttribute("href") || "", baseUrl).href;
      const text = (a.textContent || "").trim().slice(0, 80);
      // Skip anchors, mailto, tel, javascript, and file downloads
      if (href.startsWith("mailto:") || href.startsWith("tel:") || href.startsWith("javascript:") || /\.(pdf|zip|png|jpg|svg)$/i.test(href)) return;
      if (seen.has(href)) return;
      seen.add(href);
      links.push({ href, text });
    } catch {}
  });
  return links;
}

// Fetch sitemap.xml and extract URLs (via CORS proxy)
async function fetchSitemapUrls(baseUrl: string): Promise<string[]> {
  try {
    const u = new URL(baseUrl);
    const sitemapUrl = `${u.protocol}//${u.host}/sitemap.xml`;
    const xml = await fetchPageHTML(sitemapUrl); // uses CORS proxy
    if (!xml || xml.length < 50) return [];
    const urls: string[] = [];
    const locRegex = /<loc>([^<]+)<\/loc>/g;
    let match;
    while ((match = locRegex.exec(xml)) !== null) urls.push(match[1]);
    return urls;
  } catch { return []; }
}

// Discover subdomains from HTML links
function extractSubdomains(html: string, baseUrl: string): string[] {
  try {
    const baseDomain = new URL(baseUrl).hostname.replace(/^www\./, "");
    const subdomains = new Set<string>();
    const hrefRegex = /href=["'](https?:\/\/[^"']+)["']/g;
    let match;
    while ((match = hrefRegex.exec(html)) !== null) {
      try {
        const host = new URL(match[1]).hostname;
        if (host !== baseDomain && host.endsWith(baseDomain) && !host.includes("cdn") && !host.includes("static")) {
          subdomains.add(`https://${host}`);
        }
      } catch {}
    }
    return Array.from(subdomains);
  } catch { return []; }
}

// Use AI to pick which sitemap/page URLs are product/about pages
async function discoverProductPages(urls: string[], companyUrl: string): Promise<string[]> {
  if (urls.length === 0) return [];
  const urlList = urls.slice(0, 80).map((u, i) => `${i}. ${u}`).join("\n");
  try {
    const raw = await callAI(
      `You are analyzing a company's sitemap URLs to find product/service pages.\n\nWebsite: ${companyUrl}\n\nURLs found:\n${urlList}\n\nWhich URLs lead to pages describing the company's PRODUCTS, SERVICES, SOLUTIONS, or ABOUT the company? Pick the most relevant ones (max 8).\n\nSkip: blog posts, landing pages (/lp/), demos, login, legal, templates, internal pages, affiliates.\nPrioritize: product pages, about pages, solution pages, main service descriptions.\n\nReturn ONLY a JSON array of the URL numbers: [0, 3, 7]`,
      "Return only a valid JSON array of integers.", 200
    );
    const indices = JSON.parse(raw.replace(/```json|```/g, "").trim());
    if (Array.isArray(indices)) {
      return indices.filter(i => typeof i === "number" && i >= 0 && i < urls.length).map(i => urls[i]);
    }
  } catch {}
  return [];
}

function getOpenAIKey() { return localStorage.getItem("b2br_openai_key") || ""; }
function getGeminiKey() { return localStorage.getItem("b2br_gemini_key") || ""; }

async function callOpenAI(prompt: string, sys = "", tokens = 1000): Promise<string> {
  const key = getOpenAIKey();
  if (!key) throw new Error("No OpenAI API key configured");
  const msgs: any[] = [];
  if (sys) msgs.push({ role:"system", content:sys });
  msgs.push({ role:"user", content:prompt });
  const r = await fetch("https://api.openai.com/v1/chat/completions", {
    method:"POST",
    headers:{ "Content-Type":"application/json", "Authorization":`Bearer ${key}` },
    body: JSON.stringify({ model:"gpt-4o", messages:msgs, max_tokens:tokens }),
  });
  const j = await r.json();
  if (j.error) throw new Error(j.error.message);
  return j.choices?.[0]?.message?.content ?? "";
}

async function callGemini(prompt: string, tokens = 1000): Promise<string> {
  const key = getGeminiKey();
  if (!key) throw new Error("No Gemini API key configured");
  const r = await fetch(
    `https://generativelanguage.googleapis.com/v1beta/models/gemini-1.5-flash-latest:generateContent?key=${key}`,
    {
      method:"POST",
      headers:{ "Content-Type":"application/json" },
      body: JSON.stringify({
        contents:[{ parts:[{ text: prompt }] }],
        generationConfig:{ maxOutputTokens:tokens },
        systemInstruction:{ parts:[{ text:"You are a senior B2B cold outreach strategist. Be direct, specific, no filler." }] },
      }),
    }
  );
  const j = await r.json();
  console.log("Gemini raw response:", j);
  if (j.error) throw new Error(j.error.message || JSON.stringify(j.error));
  if (!j.candidates?.length) throw new Error(`Gemini returned no candidates. Full response: ${JSON.stringify(j).slice(0,300)}`);
  return j.candidates[0]?.content?.parts?.[0]?.text ?? "";
}

// Lenient JSON parser for AI responses. Handles the common failure modes:
//   1. Markdown fences (```json ... ```)
//   2. Stray prose before/after the JSON
//   3. Unescaped control characters inside string literals (raw newlines/tabs from transcript quotes)
//   4. Wrapping object like {"data": [...]} when caller expected the inner array
// Returns the parsed value or throws with the original parse error.
function safeJsonParse(raw: string): any {
  const stripped = String(raw || "").replace(/```json?\s*/gi, "").replace(/```/g, "").trim();
  // Try direct parse first (fast path)
  try { return JSON.parse(stripped); } catch {}
  // Find the JSON structure — first '{' or '[' and walk to the matching close, tracking string state
  // so we can (a) skip braces inside strings and (b) escape control chars inside strings.
  const findStructureEnd = (s: string, start: number): number => {
    const open = s[start]; if (open !== "{" && open !== "[") return -1;
    const close = open === "{" ? "}" : "]";
    let depth = 0, inStr = false, esc = false;
    for (let i = start; i < s.length; i++) {
      const ch = s[i];
      if (esc) { esc = false; continue; }
      if (ch === "\\" && inStr) { esc = true; continue; }
      if (ch === '"') { inStr = !inStr; continue; }
      if (inStr) continue;
      if (ch === open) depth++;
      else if (ch === close) { depth--; if (depth === 0) return i; }
    }
    return -1;
  };
  // Escape raw control chars (\n, \r, \t, etc.) that appear INSIDE JSON string literals.
  const escapeControlCharsInStrings = (s: string): string => {
    let out = "";
    let inStr = false, esc = false;
    for (let i = 0; i < s.length; i++) {
      const ch = s[i];
      const code = ch.charCodeAt(0);
      if (esc) { out += ch; esc = false; continue; }
      if (inStr && ch === "\\") { out += ch; esc = true; continue; }
      if (ch === '"') { out += ch; inStr = !inStr; continue; }
      if (inStr && code < 0x20) {
        // Raw control char inside a string — replace with the JSON-escaped form.
        if (ch === "\n") out += "\\n";
        else if (ch === "\r") out += "\\r";
        else if (ch === "\t") out += "\\t";
        else if (ch === "\b") out += "\\b";
        else if (ch === "\f") out += "\\f";
        else out += "\\u" + code.toString(16).padStart(4, "0");
        continue;
      }
      out += ch;
    }
    return out;
  };
  for (const opener of ["{", "["]) {
    const start = stripped.indexOf(opener);
    if (start < 0) continue;
    const end = findStructureEnd(stripped, start);
    if (end < 0) continue;
    const slice = stripped.slice(start, end + 1);
    // Try plain parse first on the sliced region
    try { return JSON.parse(slice); } catch {}
    // Retry after escaping control chars in strings
    try { return JSON.parse(escapeControlCharsInStrings(slice)); } catch {}
  }
  // Final retry on the full escaped string (in case our structure-finder missed something weird)
  try { return JSON.parse(escapeControlCharsInStrings(stripped)); } catch {}
  // Give up — let JSON.parse's error bubble up
  return JSON.parse(stripped);
}

function fileToBase64(file) {
  return new Promise((res, rej) => {
    const reader = new FileReader();
    reader.onload  = () => res(reader.result.split(",")[1]);
    reader.onerror = rej;
    reader.readAsDataURL(file);
  });
}

// Local heuristic scorer — no API calls, instant, free
function scoreWithAI(f: any, v: any): Promise<number> {
  if (!fieldFilled(f, v)) return Promise.resolve(0);
  if (f.type === "select" || f.type === "chips") return Promise.resolve(92);
  const str = Array.isArray(v) ? v.join(", ") : String(v ?? "").trim();
  if (!str) return Promise.resolve(0);
  // Score based on content quality heuristics
  let score = 50;
  const words = str.split(/\s+/).length;
  const sentences = str.split(/[.!?]+/).filter(Boolean).length;
  // Length bonus (more detail = higher confidence)
  if (words >= 5) score += 10;
  if (words >= 15) score += 10;
  if (words >= 30) score += 5;
  // Specificity bonus (numbers, names, concrete details)
  if (/\d/.test(str)) score += 8; // contains numbers
  if (/[$%]/.test(str)) score += 5; // contains currency/percentage
  if (/[A-Z][a-z]+\s[A-Z]/.test(str)) score += 5; // proper nouns
  // Penalty for vagueness
  if (/various|multiple|different|several|many|some|etc/i.test(str)) score -= 10;
  if (/TBD|tbd|N\/A|n\/a|unknown|TODO/i.test(str)) score -= 20;
  // Multi-sentence bonus
  if (sentences >= 2) score += 5;
  return Promise.resolve(Math.min(100, Math.max(20, score)));
}

function newICP(idx, data = {}, name = "", confidence = {}) {
  return { id:uid(), color:ICP_COLORS[idx%ICP_COLORS.length], name, data, outputs:null,
           approval:"draft", sectionApprovals:{}, comments:[], confidence,
           linkedProductIds:[] as string[], linkedOfferIds:[] as string[] };
}

// Naming rules injected into every AI prompt that generates product/persona names
const NAMING_RULES = {
  persona: `PERSONA NAMING RULES (strict):
- Format: "[Industry/Vertical] — [Buyer Role]"
- Examples: "SaaS — VP Sales", "Construction SMB — Owner/GM", "Healthcare — IT Director", "FinTech — CFO/Controller", "Manufacturing — Ops Manager"
- Keep under 40 characters. No marketing fluff, no full sentences.
- Industry should be specific enough to differentiate from other personas (not just "Technology").
- Role should be the actual job title or function they hold, not a description of behavior.
- If the persona spans multiple industries, pick the primary one or use the sector: "B2B Services — Procurement Lead".`,
  product: `PRODUCT NAMING RULES (strict):
- USE THE EXACT PRODUCT NAME as it appears on the company's website. Do NOT rename, paraphrase, or genericize products.
- If the website calls it "Bebop RTSL", the name is "Bebop RTSL" — not "Real-Time Scripting Language" or "Automation Platform".
- If the website calls it "HubSpot Marketing Hub", the name is "HubSpot Marketing Hub" — not "Marketing Automation".
- Only simplify names when the company uses excessive marketing fluff like "Ultimate Enterprise Suite Pro 360".
- Keep under 40 characters. Preserve the company's branding and product identity.`,
};

function fieldFilled(f, val) {
  if (!val) return false;
  if (Array.isArray(val)) return val.length > 0;
  return String(val).trim().length > 0;
}

// ─── CONFIDENCE PILL ─────────────────────────────────────────────────────────
function confTip(score: number, label: string): string {
  if (score >= 95) return "High confidence — verified or strongly supported by source data.";
  if (score >= 80) return `Good confidence. To improve: add more specific details, real examples, or exact numbers to "${label}".`;
  if (score >= 55) return `Moderate confidence — this is a reasonable inference. To improve: verify with the client, add concrete specifics, named examples, or supporting data to "${label}".`;
  return `Low confidence — this is an educated guess. "${label}" needs direct client input or verified source data to be reliable.`;
}

function ConfPill({ score, label="" }: { score:any; label?:string }) {
  if (score === undefined || score === null) return null;
  const [hover, setHover] = useState(false);
  const { color, bg } = score >= 80 ? { color:C.green, bg:C.greenLo }
    : score >= 55 ? { color:C.amber, bg:C.amberLo }
    : { color:C.red, bg:C.redLo };
  return (
    <span style={{ position:"relative", display:"inline-flex" }}
      onMouseEnter={()=>setHover(true)} onMouseLeave={()=>setHover(false)}>
      <span style={{ display:"inline-flex", alignItems:"center", gap:3,
        fontSize:9, fontFamily:mono, fontWeight:700, cursor:"default",
        color, background:bg, padding:"1px 6px", borderRadius:4, marginLeft:5 }}>
        {score}%
      </span>
      {hover && (
        <div style={{ position:"absolute", top:"100%", left:0, marginTop:6, width:260, padding:"10px 12px",
          background:C.canvas, border:`1px solid ${C.border}`, borderRadius:8,
          boxShadow:"0 8px 24px rgba(13,15,26,.15)", zIndex:100,
          fontSize:11, fontFamily:body, color:C.textSoft, lineHeight:1.5,
          animation:"toastIn .3s cubic-bezier(0.16, 1, 0.3, 1)", willChange:"opacity, transform" }}>
          <div style={{ fontSize:9, fontFamily:mono, fontWeight:700, color, marginBottom:4 }}>
            {score >= 95 ? "VERIFIED" : score >= 80 ? "GOOD" : score >= 55 ? "NEEDS REVIEW" : "LOW CONFIDENCE"}
          </div>
          {confTip(score, label)}
        </div>
      )}
    </span>
  );
}

// ─── STATUS BADGE ─────────────────────────────────────────────────────────────
function StatusBadge({ status, size="sm" }) {
  const cfg = APPROVAL_CFG[status] ?? APPROVAL_CFG.draft;
  return (
    <span style={{ display:"inline-flex", alignItems:"center", gap:5,
      fontSize: size==="xs" ? 9 : 10, fontFamily:mono, fontWeight:700,
      color:cfg.text, background:cfg.bg,
      padding: size==="xs" ? "1px 7px" : "3px 9px", borderRadius:5 }}>
      <span style={{ width:5, height:5, borderRadius:"50%", background:cfg.dot, display:"inline-block", flexShrink:0 }} />
      {cfg.label}
    </span>
  );
}

// ─── FIELD ────────────────────────────────────────────────────────────────────
function Field({ f, val, onChange, onAI, aiOn, accentColor, confidence, locked = false, onUnlock = null, onSave = null, onCancel = null, aiOptions = null, onOptionPick = null, onSubmitField = null }) {
  const filled  = fieldFilled(f, val);
  const canAI   = f.type !== "select" && f.type !== "chips" && !f.noConf;
  const isThinking = aiOn === f.id;

  const [popOpen,  setPopOpen]  = useState(false);
  const [customTx, setCustomTx] = useState("");
  const [hintOpen, setHintOpen] = useState(false);
  const [fieldHov, setFieldHov] = useState(false);
  const [popPos,   setPopPos]   = useState<{top:number;left:number}|null>(null);
  const popRef  = useRef<HTMLDivElement>(null);
  const popContentRef = useRef<HTMLDivElement>(null);
  const aiBtnRef = useRef<HTMLButtonElement>(null);

  // Close popover on outside click
  useEffect(() => {
    if (!popOpen) return;
    const handler = e => { if (popRef.current && !popRef.current.contains(e.target) && (!popContentRef.current || !popContentRef.current.contains(e.target))) { setPopOpen(false); setFieldHov(false); } };
    document.addEventListener("mousedown", handler);
    return () => document.removeEventListener("mousedown", handler);
  }, [popOpen]);

  const triggerAI = (instructions) => {
    setPopOpen(false);
    setCustomTx("");
    onAI(f, instructions || null);
  };

  const base = {
    width:"100%", padding:"9px 12px", borderRadius:7,
    border:`1.5px solid ${filled ? C.borderHi : C.border}`,
    background:C.canvas, color:C.text, fontSize:13.5, fontFamily:body, lineHeight:1.65,
    outline:"none", transition:"border-color .15s, box-shadow .15s",
  };
  const focusOn  = e => { e.target.style.borderColor=accentColor+"66"; e.target.style.boxShadow=`0 0 0 3px ${accentColor}12`; };
  const focusOff = e => { e.target.style.borderColor=fieldFilled(f,val)?C.borderHi:C.border; e.target.style.boxShadow="none"; };

  // AI icon button (rendered inside input wrapper on hover)
  const aiIcon = canAI && (
    <div style={{ position:"relative" }} ref={popRef}>
      <button
        ref={aiBtnRef}
        onClick={() => { if (!aiOn) { const r = aiBtnRef.current?.getBoundingClientRect(); if (r) setPopPos({ top: r.bottom + 7, left: Math.max(r.right - 260, 8) }); setPopOpen(p => !p); } }}
        disabled={!!aiOn}
        title="AI fill"
        style={{
          width:32, height:32, borderRadius:8, border:"none",
          background: isThinking ? C.border : accentColor,
          color:"#fff", fontSize:20, fontFamily:mono, fontWeight:700,
          cursor: isThinking ? "default" : "pointer",
          display:"flex", alignItems:"center", justifyContent:"center",
          opacity: isThinking ? .5 : (fieldHov || popOpen) ? 1 : 0,
          transition:"opacity .2s, box-shadow .2s",
          flexShrink:0, position:"relative", overflow:"hidden",
          boxShadow: popOpen ? `0 2px 12px ${accentColor}66` : (fieldHov ? `0 2px 8px ${accentColor}44` : "none"),
        }}>
        {(fieldHov || popOpen) && !isThinking && (
          <span style={{
            position:"absolute", top:0, left:0, width:"40%", height:"100%",
            background:"linear-gradient(105deg, transparent 20%, rgba(255,255,255,0.45) 50%, transparent 80%)",
            animation:"aiSheen 2.4s ease-in-out infinite",
            pointerEvents:"none",
          }} />
        )}
        {isThinking
          ? <span style={{ animation:"pulse 1.2s infinite", display:"inline-block" }}>✦</span>
          : <span style={{ animation:(fieldHov||popOpen)?"aiSpark 2s linear infinite":"none", display:"inline-block", lineHeight:1 }}>✦</span>}
      </button>

      {/* ── Popover (portal → renders in document.body, escapes all stacking contexts) ── */}
      {popOpen && !aiOn && popPos && createPortal(
        <div ref={popContentRef} style={{
          position:"fixed", top:popPos.top, left:popPos.left, zIndex:2147483647,
          width:260, background:C.canvas,
          border:`1.5px solid ${accentColor}33`,
          borderRadius:10, boxShadow:`0 8px 32px rgba(13,15,26,0.16), 0 0 0 1px ${accentColor}11`,
          animation:"fadeIn .15s ease", overflow:"hidden",
        }}>
          <div style={{ padding:"10px 12px 8px", borderBottom:`1px solid ${C.border}` }}>
            <div style={{ fontSize:10, fontFamily:mono, fontWeight:700, color:accentColor, letterSpacing:.4 }}>
              ✦ AI FILL — {f.label.toUpperCase()}
            </div>
          </div>
          <div style={{ padding:"10px 12px" }}>
            <button onClick={() => triggerAI(null)} style={{
              display:"flex", alignItems:"center", justifyContent:"space-between",
              width:"100%", padding:"9px 12px", borderRadius:7,
              border:`1.5px solid ${accentColor}33`, background:accentColor+"0D",
              cursor:"pointer", transition:"all .15s", marginBottom:10,
            }}
              onMouseEnter={e=>{ e.currentTarget.style.background=accentColor+"1A"; e.currentTarget.style.borderColor=accentColor+"66"; }}
              onMouseLeave={e=>{ e.currentTarget.style.background=accentColor+"0D"; e.currentTarget.style.borderColor=accentColor+"33"; }}>
              <div style={{ textAlign:"left" }}>
                <div style={{ fontSize:11.5, fontFamily:head, fontWeight:700, color:accentColor }}>Generate now</div>
                <div style={{ fontSize:10, color:C.muted, fontFamily:body, marginTop:1 }}>Use company + ICP context</div>
              </div>
              <span style={{ fontSize:16, color:accentColor }}>→</span>
            </button>
            <div style={{ display:"flex", alignItems:"center", gap:8, marginBottom:10 }}>
              <div style={{ flex:1, height:1, background:C.border }} />
              <span style={{ fontSize:9, color:C.muted, fontFamily:mono }}>OR</span>
              <div style={{ flex:1, height:1, background:C.border }} />
            </div>
            <div style={{ marginBottom:8 }}>
              <div style={{ fontSize:10, fontFamily:mono, fontWeight:600, color:C.textSoft, marginBottom:5 }}>Add instructions</div>
              <textarea value={customTx} onChange={e=>setCustomTx(e.target.value)}
                placeholder={`e.g. "Focus on mid-market SaaS. Keep it under 2 sentences."`}
                rows={3} autoFocus
                style={{ width:"100%", padding:"8px 10px", borderRadius:7, border:`1.5px solid ${C.border}`,
                  background:C.faint, color:C.text, fontSize:11.5, fontFamily:body, lineHeight:1.5,
                  outline:"none", resize:"none", transition:"border-color .15s" }}
                onFocus={e=>{e.target.style.borderColor=accentColor+"66";e.target.style.background=C.canvas;}}
                onBlur={e=>{e.target.style.borderColor=C.border;e.target.style.background=C.faint;}}
                onKeyDown={e=>{if(e.key==="Enter"&&(e.metaKey||e.ctrlKey))triggerAI(customTx);}} />
            </div>
            <button onClick={()=>triggerAI(customTx)} disabled={!customTx.trim()}
              style={{ width:"100%", padding:"8px", borderRadius:7, border:"none",
                background:customTx.trim()?accentColor:C.border,
                color:customTx.trim()?"#fff":C.muted,
                fontSize:11, fontFamily:head, fontWeight:700,
                cursor:customTx.trim()?"pointer":"default",
                boxShadow:customTx.trim()?`0 2px 10px ${accentColor}40`:"none",
                transition:"all .15s" }}>
              Generate with instructions {customTx.trim()?"↵":""}
            </button>
            <div style={{ fontSize:9, color:C.muted, fontFamily:mono, textAlign:"center", marginTop:6 }}>⌘↵ to generate</div>
          </div>
        </div>
      , document.body)}
    </div>
  );

  const lockedStyle = { background:C.faint, color:C.textSoft, cursor:"default" as const };
  const btnHover = { transition:"all .25s cubic-bezier(0.16, 1, 0.3, 1), transform .2s cubic-bezier(0.16, 1, 0.3, 1)" };
  const pencilBtn = locked ? (
    <button onClick={e=>{ (e.currentTarget as HTMLElement).style.animation="btnPress .3s cubic-bezier(0.16, 1, 0.3, 1)"; setTimeout(()=>{if(e.target)(e.target as HTMLElement).style.animation="";},300); onUnlock?.(); }} title="Edit field"
      style={{ marginLeft:"auto", width:22, height:22, borderRadius:5, border:`1px solid ${C.border}`,
        background:"transparent", color:C.muted, cursor:"pointer", flexShrink:0,
        display:"flex", alignItems:"center", justifyContent:"center", ...btnHover }}
      onMouseEnter={e=>{ const b=e.currentTarget as HTMLElement; b.style.color=C.text; b.style.borderColor=C.borderHi; b.style.transform="scale(1.15)"; }}
      onMouseLeave={e=>{ const b=e.currentTarget as HTMLElement; b.style.color=C.muted; b.style.borderColor=C.border; b.style.transform="scale(1)"; }}>
      <svg width="11" height="11" viewBox="0 0 12 12" fill="none">
        <path d="M8.5 1.5L10.5 3.5L3.5 10.5H1.5V8.5L8.5 1.5Z" stroke="currentColor" strokeWidth="1.3" strokeLinecap="round" strokeLinejoin="round"/>
        <path d="M7 3L9 5" stroke="currentColor" strokeWidth="1.3" strokeLinecap="round"/>
      </svg>
    </button>
  ) : onSave ? (
    <div style={{ display:"flex", gap:4, marginLeft:"auto" }}>
      <button onClick={e=>{ (e.currentTarget as HTMLElement).style.animation="btnPress .3s cubic-bezier(0.16, 1, 0.3, 1)"; setTimeout(()=>{if(e.target)(e.target as HTMLElement).style.animation="";},300); const el=document.querySelector(`[data-field-id="${f.id}"]`) as HTMLElement; if(el){el.style.animation="fieldLock .6s ease";setTimeout(()=>{el.style.animation="";},600);} onSave?.(); }} title="Save field"
        style={{ width:22, height:22, borderRadius:5, border:`1px solid ${C.greenBorder}`,
          background:"transparent", color:C.green, cursor:"pointer", flexShrink:0,
          display:"flex", alignItems:"center", justifyContent:"center",
          animation:"btnPop .3s cubic-bezier(0.16, 1, 0.3, 1)", ...btnHover }}
        onMouseEnter={e=>{ const b=e.currentTarget as HTMLElement; b.style.background=C.greenLo; b.style.transform="scale(1.15)"; }}
        onMouseLeave={e=>{ const b=e.currentTarget as HTMLElement; b.style.background="transparent"; b.style.transform="scale(1)"; }}>
        <svg width="10" height="10" viewBox="0 0 10 10" fill="none"><path d="M1.5 5L4 7.5L8.5 2.5" stroke="currentColor" strokeWidth="1.4" strokeLinecap="round" strokeLinejoin="round"/></svg>
      </button>
      <button onClick={e=>{ (e.currentTarget as HTMLElement).style.animation="btnPress .3s cubic-bezier(0.16, 1, 0.3, 1)"; setTimeout(()=>{if(e.target)(e.target as HTMLElement).style.animation="";},300); const el=document.querySelector(`[data-field-id="${f.id}"]`) as HTMLElement; if(el){el.style.animation="fieldCancel .6s ease";setTimeout(()=>{el.style.animation="";},600);} onCancel?.(); }} title="Discard changes"
        style={{ width:22, height:22, borderRadius:5, border:`1px solid ${C.border}`,
          background:"transparent", color:C.muted, cursor:"pointer", flexShrink:0,
          display:"flex", alignItems:"center", justifyContent:"center", fontSize:11,
          animation:"btnPop .3s cubic-bezier(0.16, 1, 0.3, 1) .05s both", ...btnHover }}
        onMouseEnter={e=>{ const b=e.currentTarget as HTMLElement; b.style.color=C.text; b.style.borderColor=C.borderHi; b.style.transform="scale(1.15)"; }}
        onMouseLeave={e=>{ const b=e.currentTarget as HTMLElement; b.style.color=C.muted; b.style.borderColor=C.border; b.style.transform="scale(1)"; }}>
        ✕
      </button>
    </div>
  ) : null;

  return (
    <div>
      {/* Label row */}
      <div style={{ display:"flex", alignItems:"center", gap:6, marginBottom:8 }}>
        <label style={{ fontSize:13, color:C.text, fontFamily:head, fontWeight:700 }}>
          {f.label}{f.required && <span style={{ color:C.accent, marginLeft:2 }}>*</span>}
        </label>
        {!f.noConf && confidence !== undefined && confidence !== null && val && (Array.isArray(val) ? val.length > 0 : String(val).trim().length > 0) && <ConfPill score={confidence} label={f.label} />}
        {f.hint && (
          <div style={{ position:"relative", display:"inline-flex" }}>
            <div onMouseEnter={()=>setHintOpen(true)} onMouseLeave={()=>setHintOpen(false)}
              style={{ width:15, height:15, borderRadius:"50%", border:`1px solid ${C.borderHi}`,
                display:"flex", alignItems:"center", justifyContent:"center",
                fontSize:9, fontFamily:mono, fontWeight:700, color:C.muted,
                cursor:"default", userSelect:"none" as const, flexShrink:0 }}>
              i
            </div>
            {hintOpen && (
              <div style={{ position:"absolute", left:0, top:"calc(100% + 6px)", zIndex:400,
                width:220, background:C.canvas, border:`1px solid ${C.border}`,
                borderRadius:8, padding:"8px 10px", boxShadow:"0 4px 16px rgba(13,15,26,.12)",
                fontSize:11.5, color:C.textSoft, fontFamily:body, lineHeight:1.5,
                pointerEvents:"none" as const }}>
                {f.hint}
              </div>
            )}
          </div>
        )}
        {pencilBtn}
      </div>

      {/* Input area */}
      {f.type==="chips" ? (
        <div style={{ display:"flex", flexWrap:"wrap", gap:7, pointerEvents: locked ? "none" : "auto", opacity: locked ? 0.5 : 1 }}>
          {f.opts.map(o => {
            const on = (val||[]).includes(o);
            return (
              <button key={o} onClick={()=>onChange(on?(val||[]).filter(v=>v!==o):[...(val||[]),o])}
                style={{ padding:"5px 14px", borderRadius:20, fontSize:12, fontFamily:mono,
                  border:`1.5px solid ${on?accentColor+"55":C.border}`,
                  background:on?accentColor+"10":C.canvas, color:on?accentColor:C.muted,
                  cursor:"pointer", transition:"all .15s", fontWeight:on?700:400 }}>
                {o}
              </button>
            );
          })}
        </div>
      ) : f.type==="select" ? (
        <div style={{ pointerEvents: locked ? "none" : "auto", opacity: locked ? 0.5 : 1 }}>
          <select value={val||""} onChange={e=>onChange(e.target.value)}
            style={{...base, cursor:"pointer", ...(locked ? lockedStyle : {})}}
            onFocus={focusOn} onBlur={focusOff}>
            <option value="">Select…</option>
            {f.opts.map(o=><option key={o} value={o}>{o}</option>)}
          </select>
        </div>
      ) : (
        <div style={{ position:"relative" }}
          onMouseEnter={()=>{ if(!locked) setFieldHov(true); }}
          onMouseLeave={()=>setFieldHov(false)}>
          {f.type==="textarea"
            ? <textarea data-field-id={f.id} value={val||""} onChange={e=>onChange(e.target.value)} placeholder={f.ph} rows={f.rows||2}
                readOnly={locked}
                style={{...base, resize:"vertical", paddingRight: canAI ? 44 : 12, ...(locked ? lockedStyle : {}), transition:"box-shadow .5s ease"}}
                onFocus={focusOn} onBlur={focusOff}
                onKeyDown={e=>{ if(e.key==="Enter"&&(e.metaKey||e.ctrlKey)&&!locked&&val&&String(val).trim()) { e.preventDefault(); e.currentTarget.style.animation="fieldLock .6s ease"; setTimeout(()=>{if(e.target)(e.target as HTMLElement).style.animation="";},600); onSave?.(); onSubmitField?.(f.id); } }} />
            : <input data-field-id={f.id} type="text" value={val||""} onChange={e=>onChange(e.target.value)} placeholder={f.ph}
                readOnly={locked}
                style={{...base, paddingRight: canAI ? 44 : 12, ...(locked ? lockedStyle : {}), transition:"box-shadow .5s ease"}}
                onFocus={focusOn} onBlur={focusOff}
                onKeyDown={e=>{ if(e.key==="Enter"&&!locked&&val&&String(val).trim()) { e.preventDefault(); e.currentTarget.style.animation="fieldLock .6s ease"; setTimeout(()=>{if(e.target)(e.target as HTMLElement).style.animation="";},600); onSave?.(); onSubmitField?.(f.id); } }} />
          }
          {canAI && !locked && (
            <div style={{ position:"absolute", right:6, top:"50%", transform:"translateY(-50%)", zIndex:10 }}>
              {aiIcon}
            </div>
          )}
          {f.type==="textarea" && !locked && (
            <div style={{ position:"absolute", bottom:5, right:5, pointerEvents:"none", zIndex:5, opacity:.45 }}>
              <svg width="18" height="18" viewBox="0 0 18 18" fill="none">
                <circle cx="14" cy="4"  r="1.6" fill={C.muted}/>
                <circle cx="9"  cy="9"  r="1.6" fill={C.muted}/>
                <circle cx="14" cy="9"  r="1.6" fill={C.muted}/>
                <circle cx="4"  cy="14" r="1.6" fill={C.muted}/>
                <circle cx="9"  cy="14" r="1.6" fill={C.muted}/>
                <circle cx="14" cy="14" r="1.6" fill={C.muted}/>
              </svg>
            </div>
          )}
        </div>
      )}

      {/* AI options picker */}
      {aiOptions && aiOptions.length > 0 && (
        <div style={{ marginTop:8, borderRadius:10, border:`1.5px solid ${accentColor}33`,
          background:C.canvas, overflow:"hidden", animation:"fadeIn .15s ease" }}>
          <div style={{ padding:"8px 12px 6px", borderBottom:`1px solid ${C.border}`,
            display:"flex", alignItems:"center", justifyContent:"space-between" }}>
            <div style={{ fontSize:10, fontFamily:mono, fontWeight:700, color:accentColor, letterSpacing:.4 }}>
              ✦ PICK AN OPTION — {f.label.toUpperCase()}
            </div>
            <button onClick={()=>onOptionPick && onOptionPick(null)}
              style={{ background:"none", border:"none", cursor:"pointer", color:C.muted, fontSize:13, lineHeight:1, padding:2 }}>✕</button>
          </div>
          {aiOptions.map((opt, i) => {
            const { color: sc, bg: sb } = opt.conf >= 80 ? { color:C.green, bg:C.greenLo }
              : opt.conf >= 55 ? { color:C.amber, bg:C.amberLo }
              : { color:C.red, bg:C.redLo };
            return (
              <div key={i}
                onClick={()=>onOptionPick && onOptionPick(opt)}
                style={{ padding:"10px 12px", borderBottom: i < aiOptions.length-1 ? `1px solid ${C.border}` : "none",
                  cursor:"pointer", display:"flex", alignItems:"flex-start", gap:10, transition:"background .12s" }}
                onMouseEnter={e=>(e.currentTarget as HTMLDivElement).style.background=accentColor+"0A"}
                onMouseLeave={e=>(e.currentTarget as HTMLDivElement).style.background="transparent"}>
                <span style={{ fontSize:9, fontFamily:mono, fontWeight:700, color:C.muted, marginTop:2, flexShrink:0 }}>
                  {i+1}.
                </span>
                <div style={{ flex:1, fontSize:12.5, fontFamily:body, color:C.text, lineHeight:1.55 }}>
                  {opt.text}
                </div>
                <span style={{ fontSize:9, fontFamily:mono, fontWeight:700, color:sc, background:sb,
                  padding:"2px 6px", borderRadius:4, flexShrink:0, marginTop:1 }}>
                  {opt.conf}%
                </span>
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
}

// ─── TOAST STACK ──────────────────────────────────────────────────────────────
type Toast = { id:string; title:string; message?:string; status:"loading"|"success"|"error"; action?:{ label:string; onClick:()=>void }; step?:number; totalSteps?:number; startTime?:number };
function ToastCard({ t, dismiss }: { t:Toast; dismiss:(id:string)=>void }) {
  return (
    <div style={{ display:"flex", alignItems:"flex-start", gap:10 }}>
      <div style={{ flexShrink:0, width:18, textAlign:"center", marginTop:1 }}>
        {t.status==="loading" && <span style={{ animation:"aiSpark 1.2s linear infinite", display:"inline-block", color:C.accent, fontSize:13 }}>✦</span>}
        {t.status==="success" && <span style={{ color:C.green, fontSize:14, fontWeight:700 }}>✓</span>}
        {t.status==="error"   && <span style={{ color:C.red,   fontSize:14, fontWeight:700 }}>✕</span>}
      </div>
      <div style={{ flex:1, minWidth:0 }}>
        <div style={{ fontSize:12.5, fontWeight:700, color:C.text, fontFamily:head, lineHeight:1.3 }}>{t.title}</div>
        {t.message && <div style={{ fontSize:11, color:C.muted, fontFamily:body, marginTop:2, lineHeight:1.4 }}>{t.message}</div>}
        {t.status==="loading" && t.step != null && t.totalSteps && (
          <div style={{ marginTop:6 }}>
            <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between", marginBottom:3 }}>
              <span style={{ fontSize:9, fontFamily:mono, color:C.muted }}>{t.step}/{t.totalSteps} steps</span>
              {t.startTime && (() => {
                const elapsed = Math.round((Date.now() - t.startTime) / 1000);
                const perStep = t.step! > 0 ? elapsed / t.step! : 0;
                const remaining = Math.round(perStep * (t.totalSteps! - t.step!));
                return remaining > 0 ? (
                  <span style={{ fontSize:9, fontFamily:mono, color:C.muted }}>~{remaining}s left</span>
                ) : null;
              })()}
            </div>
            <div style={{ height:3, background:C.faint, borderRadius:2, overflow:"hidden" }}>
              <div style={{ height:"100%", width:`${(t.step / t.totalSteps) * 100}%`,
                background:C.accent, borderRadius:2, transition:"width .6s cubic-bezier(0.16, 1, 0.3, 1)" }} />
            </div>
          </div>
        )}
        {t.action && (
          <button onClick={()=>{ t.action!.onClick(); dismiss(t.id); }}
            style={{ marginTop:6, fontSize:11, color:C.accent, fontFamily:head, fontWeight:700,
              background:"none", border:"none", cursor:"pointer", padding:0 }}>
            {t.action.label} →
          </button>
        )}
      </div>
      {t.status !== "loading" && (
        <button onClick={()=>dismiss(t.id)}
          style={{ flexShrink:0, background:"none", border:"none", cursor:"pointer",
            color:C.muted, fontSize:14, padding:0, lineHeight:1, marginTop:1 }}
          onMouseEnter={e=>(e.currentTarget as HTMLButtonElement).style.color=C.text}
          onMouseLeave={e=>(e.currentTarget as HTMLButtonElement).style.color=C.muted}>✕</button>
      )}
    </div>
  );
}

function ToastStack({ toasts, onRemove }: { toasts:Toast[]; onRemove:(id:string)=>void }) {
  const [exiting, setExiting] = useState<Set<string>>(new Set());
  const [activeIdx, setActiveIdx] = useState(0);
  const [animKey, setAnimKey] = useState(0);
  const animRef = useRef<string>("toastIn .4s cubic-bezier(0.16, 1, 0.3, 1)");

  const dismiss = (id: string) => {
    setExiting(prev => new Set(prev).add(id));
    setTimeout(() => { setExiting(prev => { const n = new Set(prev); n.delete(id); return n; }); onRemove(id); }, 300);
  };

  const visible = toasts.filter(t => !exiting.has(t.id));
  const idx = Math.min(activeIdx, Math.max(0, visible.length - 1));
  const TOAST_W = 320;

  const cycle = (dir: "fwd"|"back") => {
    animRef.current = `${dir==="fwd"?"cardPullForward":"cardPushBack"} .35s cubic-bezier(0.16, 1, 0.3, 1)`;
    setAnimKey(k => k + 1);
    setActiveIdx(i => dir === "fwd" ? (i + 1) % visible.length : (i - 1 + visible.length) % visible.length);
  };

  if (!visible.length) return null;

  // Build the 3-card stack: active on top, next two behind
  const stack = [0, 1, 2].map(depth => {
    const i = (idx + depth) % visible.length;
    return visible[i];
  }).filter(Boolean);

  return (
    <div style={{ position:"fixed", bottom:24, right:24, zIndex:99999, pointerEvents:"none", width:TOAST_W }}>
      {/* 3-card stack */}
      <div style={{ position:"relative" }}>
        {/* Cards behind (depth 2, then 1) — rendered first so they're behind */}
        {visible.length > 2 && stack[2] && (
          <div key={`bg2-${stack[2].id}`} style={{
            position:"absolute", bottom: -8, left: 14, right: 14, height: 50,
            background:C.canvas, borderRadius:8,
            border:`1px solid ${stack[2].status==="success"?C.green+"22":stack[2].status==="error"?C.red+"22":C.border}`,
            boxShadow:"0 2px 8px rgba(13,15,26,.06)",
            opacity:.4, zIndex:1,
            transition:"all .4s cubic-bezier(0.16, 1, 0.3, 1)",
          }} />
        )}
        {visible.length > 1 && stack[1] && (
          <div key={`bg1-${stack[1].id}`} style={{
            position:"absolute", bottom: -4, left: 7, right: 7, height: 54,
            background:C.canvas, borderRadius:9,
            border:`1px solid ${stack[1].status==="success"?C.green+"33":stack[1].status==="error"?C.red+"33":C.border}`,
            boxShadow:"0 3px 12px rgba(13,15,26,.08)",
            opacity:.6, zIndex:2,
            transition:"all .4s cubic-bezier(0.16, 1, 0.3, 1)",
          }} />
        )}

        {/* Active card on top */}
        {stack[0] && (
          <div key={animKey} style={{
            position:"relative", zIndex:3, pointerEvents:"all",
            background:C.canvas, borderRadius:10, padding:"12px 14px",
            border:`1.5px solid ${stack[0].status==="success"?C.green+"55":stack[0].status==="error"?C.red+"55":C.accentBorder}`,
            boxShadow:"0 4px 24px rgba(13,15,26,.18)",
            width:TOAST_W, boxSizing:"border-box" as const,
            display:"flex", flexDirection:"column" as const,
            animation: animRef.current,
            willChange:"opacity, transform",
          }}>

            <div style={{ flex:1, minHeight:0, overflow:"hidden" }}>
              <ToastCard t={stack[0]} dismiss={dismiss} />
            </div>

            {/* Navigation — card cycling */}
            {visible.length > 1 && (
              <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between", marginTop:8,
                paddingTop:8, borderTop:`1px solid ${C.border}` }}>
                <button onClick={()=>cycle("back")}
                  style={{ background:"none", border:`1px solid ${C.border}`, color:C.muted, fontSize:11, fontFamily:mono,
                    cursor:"pointer", padding:"3px 10px", borderRadius:5, lineHeight:1,
                    transition:"all .2s cubic-bezier(0.16, 1, 0.3, 1)" }}
                  onMouseEnter={e=>{const b=e.currentTarget as HTMLButtonElement;b.style.color=C.text;b.style.borderColor=C.accentBorder;b.style.transform="translateY(-1px)";}}
                  onMouseLeave={e=>{const b=e.currentTarget as HTMLButtonElement;b.style.color=C.muted;b.style.borderColor=C.border;b.style.transform="translateY(0)";}}>↑</button>
                <span style={{ fontSize:9, fontFamily:mono, color:C.muted, fontWeight:600 }}>
                  {idx + 1} of {visible.length}
                </span>
                <button onClick={()=>cycle("fwd")}
                  style={{ background:"none", border:`1px solid ${C.border}`, color:C.muted, fontSize:11, fontFamily:mono,
                    cursor:"pointer", padding:"3px 10px", borderRadius:5, lineHeight:1,
                    transition:"all .2s cubic-bezier(0.16, 1, 0.3, 1)" }}
                  onMouseEnter={e=>{const b=e.currentTarget as HTMLButtonElement;b.style.color=C.text;b.style.borderColor=C.accentBorder;b.style.transform="translateY(1px)";}}
                  onMouseLeave={e=>{const b=e.currentTarget as HTMLButtonElement;b.style.color=C.muted;b.style.borderColor=C.border;b.style.transform="translateY(0)";}}>↓</button>
              </div>
            )}
          </div>
        )}
      </div>
    </div>
  );
}

// ─── PROGRESS BAR ─────────────────────────────────────────────────────────────
function ProgressBar({ pct, color=C.accent, height=3 }) {
  return (
    <div style={{ height, background:C.faint, borderRadius:height, overflow:"hidden" }}>
      <div style={{ height:"100%", width:`${pct}%`, background:color, borderRadius:height,
        transition:"width .6s cubic-bezier(0.16, 1, 0.3, 1), background .4s ease",
        boxShadow: pct >= 100 ? `0 0 6px ${color}44` : "none" }} />
    </div>
  );
}

// ─── INTAKE NORMALIZATION ─────────────────────────────────────────────────────
// Build text context from workspace files for AI consumption
function buildFileContext(files: any[]): string {
  if (!files || !files.length) return "";
  const parts: string[] = [];
  for (const f of files) {
    if (!f.b64 || f._loading || f._failed) continue;
    if (f.type?.includes("word") || f.name?.endsWith(".docx") || f.name?.endsWith(".doc")) {
      try {
        const raw = atob(f.b64);
        const texts: string[] = [];
        const regex = /<w:t[^>]*>([^<]+)<\/w:t>/g;
        let m;
        while ((m = regex.exec(raw)) !== null && texts.length < 200) texts.push(m[1]);
        if (texts.length > 0) parts.push(`FILE "${f.name}":\n${texts.join(" ").slice(0, 4000)}`);
      } catch {}
    } else if (f.type?.startsWith("text/") || f.type?.includes("json") || f.type?.includes("csv")) {
      try { parts.push(`FILE "${f.name}":\n${atob(f.b64).slice(0, 4000)}`); } catch {}
    } else if (f.type?.startsWith("image/")) {
      parts.push(`FILE "${f.name}": [image — ${f.tags?.join(", ") || "screenshot"}]`);
    } else {
      parts.push(`FILE "${f.name}": [${f.type || "unknown type"} — ${f.tags?.join(", ") || "uploaded file"}]`);
    }
  }
  return parts.length > 0 ? "\n\nWORKSPACE FILES:\n" + parts.join("\n\n") : "";
}

function exportFullPDF(companyData: any, icps: any[], clientName: string) {
  const esc = (s: string) => (s||"").replace(/&/g,"&amp;").replace(/</g,"&lt;").replace(/>/g,"&gt;").replace(/\n/g,"<br>");
  const md2html = (text: string) => {
    if (!text) return "";
    return text.split("\n").map(line => {
      if (/^### /.test(line)) return `<h4 style="margin:12px 0 4px;font-size:13px;color:#3D4460;">${esc(line.slice(4))}</h4>`;
      if (/^## /.test(line)) return `<h3 style="margin:16px 0 6px;font-size:14px;text-transform:uppercase;letter-spacing:0.5px;color:#8892B0;">${esc(line.slice(3))}</h3>`;
      if (/^# /.test(line)) return `<h2 style="margin:20px 0 8px;font-size:18px;color:#0D0F1A;">${esc(line.slice(2))}</h2>`;
      if (/^[-•*] /.test(line)) return `<li style="margin:2px 0;color:#3D4460;">${esc(line.replace(/^[-•*] /,"")).replace(/\*\*([^*]+)\*\*/g,"<strong>$1</strong>")}</li>`;
      if (/^---+$/.test(line.trim())) return `<hr style="border:none;border-top:1px solid #E3E6EE;margin:16px 0;">`;
      if (line.trim() === "") return `<div style="height:8px;"></div>`;
      return `<p style="margin:3px 0;color:#3D4460;line-height:1.7;">${esc(line).replace(/\*\*([^*]+)\*\*/g,"<strong style='color:#0D0F1A;'>$1</strong>")}</p>`;
    }).join("");
  };

  const coFields = ALL_COMPANY_FIELDS.filter(f => companyData?.[f.id]);
  const date = new Date().toLocaleDateString("en-US", { year:"numeric", month:"long", day:"numeric" });

  let html = `<!DOCTYPE html><html><head><meta charset="utf-8"><title>${clientName} — Full Export</title>
<style>
  @import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700&display=swap');
  * { margin:0; padding:0; box-sizing:border-box; }
  body { font-family:'Inter',system-ui,sans-serif; color:#3D4460; font-size:12px; line-height:1.6; padding:0; }
  @page { margin:0.6in 0.7in; size:letter; }
  @media print { .no-print { display:none!important; } .page-break { page-break-before:always; } }
  .cover { height:100vh; display:flex; flex-direction:column; justify-content:center; align-items:center; text-align:center; page-break-after:always; }
  .cover h1 { font-size:36px; font-weight:700; color:#4F46E5; margin-bottom:8px; }
  .cover .subtitle { font-size:16px; color:#8892B0; margin-bottom:32px; }
  .cover .date { font-size:13px; color:#C4C9D9; }
  .cover .line { width:60px; height:3px; background:#4F46E5; border-radius:2px; margin:24px auto; }
  .section-title { font-size:22px; font-weight:700; color:#0D0F1A; margin:0 0 4px; padding-bottom:8px; border-bottom:2px solid #4F46E5; }
  .section-subtitle { font-size:12px; color:#8892B0; margin-bottom:20px; }
  .field-group { margin-bottom:14px; }
  .field-label { font-size:10px; font-weight:700; color:#8892B0; text-transform:uppercase; letter-spacing:0.5px; margin-bottom:3px; }
  .field-value { font-size:12px; color:#0D0F1A; line-height:1.6; }
  .icp-header { background:linear-gradient(135deg,#4F46E510,#4F46E505); border:1px solid #4F46E522; border-radius:10px; padding:16px 20px; margin-bottom:20px; }
  .icp-header h2 { font-size:20px; font-weight:700; color:#4F46E5; margin-bottom:4px; }
  .icp-header .meta { font-size:11px; color:#8892B0; }
  .output-block { margin-bottom:24px; }
  .output-title { font-size:14px; font-weight:700; color:#0D0F1A; margin-bottom:8px; padding:8px 12px; background:#F8F9FC; border-radius:6px; border-left:3px solid #4F46E5; }
  .output-content { padding:0 12px; font-size:12px; line-height:1.7; }
  .two-col { display:grid; grid-template-columns:1fr 1fr; gap:12px; }
  .badge { display:inline-block; padding:2px 8px; border-radius:4px; font-size:10px; font-weight:600; }
  .badge-green { background:#0E9E6E10; color:#0E9E6E; }
  .badge-amber { background:#F59E0B10; color:#F59E0B; }
  .badge-purple { background:#8B5CF610; color:#8B5CF6; }
  table { width:100%; border-collapse:collapse; margin:8px 0; font-size:11px; }
  th { text-align:left; padding:6px 8px; background:#F8F9FC; border-bottom:1px solid #E3E6EE; font-weight:600; color:#8892B0; font-size:10px; text-transform:uppercase; }
  td { padding:6px 8px; border-bottom:1px solid #F0F2F8; }
  .toc { margin:20px 0; }
  .toc-item { display:flex; justify-content:space-between; padding:6px 0; border-bottom:1px dotted #E3E6EE; font-size:13px; }
  .toc-item .label { color:#0D0F1A; font-weight:500; }
  .toc-item .dots { flex:1; margin:0 8px; border-bottom:1px dotted #C4C9D9; }
  .print-btn { position:fixed; bottom:24px; right:24px; padding:12px 24px; background:#4F46E5; color:#fff; border:none; border-radius:8px; font-size:14px; font-weight:700; cursor:pointer; box-shadow:0 4px 16px rgba(79,70,229,0.3); z-index:1000; }
  .print-btn:hover { background:#4338CA; }
</style></head><body>`;

  // Cover page
  html += `<div class="cover">
    <div class="line"></div>
    <h1>${esc(clientName)}</h1>
    <div class="subtitle">GTM Strategy & Campaign Package</div>
    <div class="date">${date}</div>
    <div style="margin-top:40px;font-size:11px;color:#C4C9D9;">${icps.length} ICP Profile${icps.length!==1?"s":""} · ${icps.filter(i=>i.outputs).length} with outputs generated</div>
  </div>`;

  // Table of contents
  html += `<div class="section-title">Table of Contents</div><div class="toc">`;
  html += `<div class="toc-item"><span class="label">Company Profile</span><span class="dots"></span></div>`;
  for (const icp of icps) {
    html += `<div class="toc-item"><span class="label">${esc(icp.name||"Unnamed ICP")}</span><span class="dots"></span><span class="badge ${icp.approval==="finalized"?"badge-purple":icp.approval==="approved"?"badge-green":"badge-amber"}">${icp.approval==="finalized"?"Finalized":icp.approval==="approved"?"Approved":"Draft"}</span></div>`;
    if (icp.outputs) {
      for (const t of OUTPUT_TABS) {
        if (icp.outputs[t.id]) html += `<div class="toc-item" style="padding-left:20px;"><span class="label" style="color:#8892B0;font-size:12px;">↳ ${t.label}</span><span class="dots"></span></div>`;
      }
    }
  }
  html += `</div><div class="page-break"></div>`;

  // Company Profile
  html += `<div class="section-title">Company Profile</div><div class="section-subtitle">Company details and campaign configuration</div>`;
  for (const sec of Object.values(COMPANY_SECTIONS) as any[]) {
    const filledFields = sec.fields.filter((f:any) => companyData?.[f.id]);
    if (!filledFields.length) continue;
    html += `<h3 style="font-size:13px;font-weight:700;color:#0D0F1A;margin:16px 0 8px;padding:6px 10px;background:#F8F9FC;border-radius:4px;">${esc(sec.label)}</h3>`;
    html += `<div class="two-col">`;
    for (const f of filledFields) {
      const val = companyData[f.id];
      const display = Array.isArray(val) ? val.join(", ") : String(val);
      html += `<div class="field-group"><div class="field-label">${esc(f.label)}</div><div class="field-value">${esc(display)}</div></div>`;
    }
    html += `</div>`;
  }
  html += `<div class="page-break"></div>`;

  // ICPs
  for (const icp of icps) {
    const d = icp.data || {};
    html += `<div class="icp-header"><h2>${esc(icp.name||"Unnamed ICP")}</h2>
      <div class="meta">Status: <span class="badge ${icp.approval==="finalized"?"badge-purple":icp.approval==="approved"?"badge-green":"badge-amber"}">${icp.approval==="finalized"?"✦ Finalized":icp.approval==="approved"?"✓ Approved":"Draft"}</span>
      ${icp.aiCouncil?` · Email Score: ${icp.aiCouncil.finalScore}/10`:""}
      · ${AI_FILLABLE_ICP_FIELDS.filter(f=>fieldFilled(f,d[f.id])).length}/${AI_FILLABLE_ICP_FIELDS.length} fields filled</div></div>`;

    // ICP fields by section
    for (const [,sec] of Object.entries(ICP_SECTIONS) as any[]) {
      const filledFields = sec.fields.filter((f:any) => d[f.id]);
      if (!filledFields.length) continue;
      html += `<h3 style="font-size:13px;font-weight:700;color:#0D0F1A;margin:14px 0 8px;">${esc(sec.label)}</h3>`;
      for (const f of filledFields) {
        const val = d[f.id];
        const display = Array.isArray(val) ? val.join(", ") : String(val);
        html += `<div class="field-group"><div class="field-label">${esc(f.label)}</div><div class="field-value">${esc(display)}</div></div>`;
      }
    }

    // Outputs
    if (icp.outputs) {
      html += `<div style="margin-top:20px;">`;
      for (const t of OUTPUT_TABS) {
        const content = icp.outputs[t.id];
        if (!content) continue;
        html += `<div class="output-block"><div class="output-title">${esc(t.label)}</div><div class="output-content">${md2html(content)}</div></div>`;
      }
      html += `</div>`;
    }

    // Campaign analysis
    if (icp.campaignAnalysis) {
      html += `<div class="output-block"><div class="output-title">Campaign Analysis Report</div><div class="output-content">${md2html(icp.campaignAnalysis)}</div></div>`;
    }

    html += `<div class="page-break"></div>`;
  }

  html += `<button class="print-btn no-print" onclick="window.print()">Save as PDF</button>`;
  html += `</body></html>`;

  const w = window.open("", "_blank");
  if (w) { w.document.write(html); w.document.close(); }
}

function normalizeIntake(raw: string): string {
  let t = raw;
  // Normalize line endings and collapse excessive whitespace
  t = t.replace(/\r\n/g, "\n").replace(/\n{3,}/g, "\n\n").replace(/[ \t]{2,}/g, " ");
  // Split multi-answer strings (semicolons, pipes, slashes used as separators)
  t = t.replace(/([a-zA-Z])\s*[;|\/]\s*([a-zA-Z])/g, "$1, $2");
  // Normalize common title variants
  const titleMap: Record<string,string> = {
    "vp":"VP", "ceo":"CEO", "cfo":"CFO", "coo":"COO", "cro":"CRO", "cto":"CTO", "cmo":"CMO",
    "vp of sales":"VP of Sales", "vp sales":"VP of Sales", "vice president of sales":"VP of Sales",
    "vp of marketing":"VP of Marketing", "vp marketing":"VP of Marketing", "vice president of marketing":"VP of Marketing",
    "vp of operations":"VP of Operations", "vice president operations":"VP of Operations",
    "chief executive officer":"CEO", "chief financial officer":"CFO", "chief operating officer":"COO",
    "chief revenue officer":"CRO", "chief technology officer":"CTO", "chief marketing officer":"CMO",
    "head of sales":"Head of Sales", "head of marketing":"Head of Marketing",
    "director of sales":"Director of Sales", "director of marketing":"Director of Marketing",
    "sales director":"Director of Sales", "marketing director":"Director of Marketing",
    "owner/operator":"Owner", "owner / operator":"Owner", "owner-operator":"Owner",
  };
  for (const [k, v] of Object.entries(titleMap)) {
    t = t.replace(new RegExp(`\\b${k}\\b`, "gi"), v);
  }
  // Normalize employee/company size ranges
  t = t.replace(/(\d+)\s*[-–—]\s*(\d+)\s*(employees|people|staff|headcount)/gi, "$1–$2 employees");
  t = t.replace(/(\d+)\s*\+\s*(employees|people|staff|headcount)/gi, "$1+ employees");
  // Normalize geography
  const geoMap: Record<string,string> = {
    "us":"United States", "usa":"United States", "u.s.":"United States", "u.s.a.":"United States",
    "uk":"United Kingdom", "u.k.":"United Kingdom", "gb":"United Kingdom",
    "na":"North America", "n. america":"North America", "n america":"North America",
    "emea":"EMEA", "apac":"APAC", "latam":"LATAM", "dach":"DACH", "anz":"ANZ",
  };
  for (const [k, v] of Object.entries(geoMap)) {
    t = t.replace(new RegExp(`\\b${k}\\b`, "gi"), v);
  }
  // Normalize URLs (strip trailing slashes, lowercase domain)
  t = t.replace(/(https?:\/\/[^\s,]+)/gi, url => {
    try { const u = new URL(url.replace(/\/+$/, "")); return `${u.protocol}//${u.host.toLowerCase()}${u.pathname}`; }
    catch { return url; }
  });
  // Deduplicate lines (common in copy-pasted forms)
  const lines = t.split("\n");
  const seen = new Set<string>();
  const deduped = lines.filter(l => { const k = l.trim().toLowerCase(); if (!k || !seen.has(k)) { seen.add(k); return true; } return false; });
  return deduped.join("\n").trim();
}

